    );
  };

  return (
    <div className="min-h-screen py-12 px-4 sm:px-6 lg:px-8 max-w-5xl mx-auto">
      <div className="text-center mb-10">
        <h1 className="text-4xl font-extrabold text-gray-900 tracking-tight">
          Lorebook Translator <span className="text-blue-600">with Gemini</span>
        </h1>
        <p className="mt-3 text-lg text-gray-600 max-w-2xl mx-auto">
          Translate and expand your character lorebooks effortlessly using AI.
        </p>
      </div>

      <div className="bg-white rounded-2xl shadow-xl overflow-hidden transition-all duration-300">
        <div className="p-8 space-y-8">

          {/* Section 1: Upload & Config */}
          <div className="border-b border-gray-100 pb-8 space-y-6">

            {/* File Upload */}
            <div className="flex flex-col sm:flex-row items-center justify-center gap-6">
              <input 
                type="file" 
                accept=".json" 
                ref={fileInputRef}
                onChange={handleFileChange} 
                className="hidden"
              />
              <Button 
                variant="secondary"
