              </Button>
              <span className={`text-lg font-medium ${file ? 'text-blue-600' : 'text-gray-400'}`}>
                {file ? file.name : 'No file selected'}
              </span>
            </div>

            {/* Instructions */}
            <div className="max-w-3xl mx-auto">
              <label htmlFor="instructions" className="block text-sm font-medium text-gray-700 mb-2">
                Additional Translation Instructions (Optional)
              </label>
              <textarea
                id="instructions"
                rows={3}
                className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-shadow bg-gray-50 text-gray-900"
                placeholder="e.g., Keep specific names in Pinyin, translate 'Sect' as 'Môn phái'..."
                value={instructions}
                onChange={(e) => setInstructions(e.target.value)}
              />
            </div>

            {/* Progress Bar Area */}
            {(status === AppStatus.TRANSLATING || status === AppStatus.PAUSED || translationSession) && renderProgressBar()}

            {/* Translate / Resume Button */}
            <div className="text-center">
              {status === AppStatus.PAUSED ? (
                 <Button 
                  onClick={resumeTranslation}
                  className="w-full sm:w-auto min-w-[200px] bg-yellow-600 hover:bg-yellow-700"
                  icon={<svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>}
                >
                  Resume Translation
                </Button>
              ) : (
                <Button 
                  onClick={startTranslation}
                  disabled={!file || status === AppStatus.TRANSLATING}
                  className="w-full sm:w-auto min-w-[200px]"
                  icon={status === AppStatus.TRANSLATING ? <Spinner /> : <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 5h12M9 3v2m1.048 9.5A18.022 18.022 0 016.412 9m6.088 9h7M11 21l5-10 5 10M12.751 5C11.783 10.77 8.07 15.61 3 18.129" /></svg>}
                >
                  {status === AppStatus.TRANSLATING ? ' Translating...' : 'Translate with Gemini'}
                </Button>
              )}
            </div>

            {errorMsg && (
               <div className="bg-red-50 border-l-4 border-red-500 p-4 rounded-md max-w-3xl mx-auto">
                 <p className="text-red-700">{errorMsg}</p>
               </div>
            )}
          </div>

          {/* Section 2: Results & Creative */}
          {(status === AppStatus.SUCCESS && translatedData) && (
            <div className="space-y-8 animate-fade-in">
              <div className="flex flex-col sm:flex-row items-center justify-between bg-green-50 p-6 rounded-xl border border-green-100">
                <div className="mb-4 sm:mb-0">
                  <h2 className="text-2xl font-bold text-green-800">Translation Complete!</h2>
                  <p className="text-green-600">Your lorebook has been processed successfully.</p>
                </div>
                <Button variant="secondary" onClick={handleDownload} icon={<svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>}>
                  Download JSON
                </Button>
              </div>

              {/* Preview Box */}
              <div className="bg-gray-900 rounded-xl overflow-hidden shadow-inner">
                <div className="bg-gray-800 px-4 py-2 text-xs text-gray-400 font-mono uppercase tracking-wider flex justify-between">
                  <span>Preview (First 50 lines)</span>
                </div>
                <pre className="p-4 text-green-400 font-mono text-sm h-64 overflow-y-auto custom-scrollbar">
                  {JSON.stringify(translatedData, null, 2).slice(0, 5000) + (JSON.stringify(translatedData).length > 5000 ? '...' : '')}
                </pre>
              </div>

              {/* Creative Assistant */}
              <div className="bg-blue-50 border border-blue-100 rounded-xl p-6 sm:p-8">
                <div className="text-center mb-6">
                  <h2 className="text-2xl font-bold text-blue-900 flex items-center justify-center gap-2">
                    <svg className="w-6 h-6 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                    Gemini Creative Assistant
                  </h2>
                  <p className="text-blue-700">Expand your lore using the context of your translated entries.</p>
                </div>

                <div className="grid gap-6">
                  <div>
                    <label className="block text-sm font-medium text-blue-900 mb-2">Select Lorebook Entry</label>
                    <select 
                      className="w-full p-3 border border-blue-200 rounded-lg bg-white focus:ring-2 focus:ring-blue-500 outline-none text-gray-700"
                      value={selectedEntryUid}
                      onChange={(e) => setSelectedEntryUid(e.target.value)}
                    >
                      <option value="">-- Choose an entry --</option>
                      {(Object.values(translatedData.entries) as LorebookEntry[]).map((entry) => (
                        <option key={entry.uid} value={entry.uid}>
                          {entry.comment || (entry.key && entry.key[0]) || `Entry ${entry.uid}`}
                        </option>
                      ))}
                    </select>
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-blue-900 mb-2">Your Creative Prompt</label>
                    <textarea 
                      rows={3}
                      className="w-full p-3 border border-blue-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-gray-900"
                      placeholder="e.g., Write a short backstory for this character involving a lost artifact..."
                      value={creativePrompt}
                      onChange={(e) => setCreativePrompt(e.target.value)}
                    />
                  </div>

                  <div className="text-center">
                    <Button 
                      onClick={handleCreativeGenerate} 
                      disabled={isCreativeLoading || !selectedEntryUid || !creativePrompt}
                      className="w-full sm:w-auto"
                      variant="primary"
                    >
                      {isCreativeLoading ? (
                        <span className="flex items-center gap-2">
                          <Spinner /> Generative Magic...
                        </span>
                      ) : (
                        <span className="flex items-center gap-2">
                          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.428 15.428a2 2 0 00-1.022-.547l-2.384-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z" /></svg>
                          Generate Content
                        </span>
                      )}
                    </Button>
                  </div>

                  {creativeOutput && (
                    <div className="mt-6 bg-white rounded-lg p-6 border border-blue-100 shadow-sm">
                      <h3 className="text-lg font-bold text-gray-800 mb-3">Result:</h3>
                      <div className="prose prose-blue max-w-none text-gray-700 whitespace-pre-wrap leading-relaxed">
                        {creativeOutput}
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { translateBatch, generateCreativeContent } from './services/geminiService';
import { Lorebook, LorebookEntry, AppStatus, TranslationSession } from './types';
import { Spinner } from './components/Spinner';
import { Button } from './components/Button';

// Regex to identify Vietnamese characters (to skip already translated items)
const VIETNAMESE_REGEX = /[àáạảãâầấậẩẫăằắặẳẵèéẹẻẽêềếệểễìíịỉĩòóọỏõôồốộổỗơờớợởỡùúụủũưừứựửữỳýỵỷỹđ]/i;

const BATCH_SIZE = 50;

const App: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [originalData, setOriginalData] = useState<Lorebook | null>(null);
  const [translatedData, setTranslatedData] = useState<Lorebook | null>(null);
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [instructions, setInstructions] = useState<string>('');
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // Translation Session State (for progress & resume)
  const [translationSession, setTranslationSession] = useState<TranslationSession | null>(null);
  const [progress, setProgress] = useState<number>(0);
  const [skippedBatches, setSkippedBatches] = useState<number>(0);

  // Creative Assistant State
  const [selectedEntryUid, setSelectedEntryUid] = useState<string>('');
  const [creativePrompt, setCreativePrompt] = useState<string>('');
  const [creativeOutput, setCreativeOutput] = useState<string>('');
  const [isCreativeLoading, setIsCreativeLoading] = useState<boolean>(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const selectedFile = e.target.files[0];
      setFile(selectedFile);
      setErrorMsg(null);

      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const content = event.target?.result as string;
          const json = JSON.parse(content);
          setOriginalData(json);
          // Reset previous results
          setTranslatedData(null);
          setTranslationSession(null);
          setProgress(0);
          setSkippedBatches(0);
          setStatus(AppStatus.IDLE);
        } catch (err) {
          setErrorMsg("Invalid JSON file format.");
          setFile(null);
        }
      };
      reader.readAsText(selectedFile);
    }
  };

  const extractStrings = (data: Lorebook): Set<string> => {
    const stringsToTranslate = new Set<string>();
    if (!data.entries || typeof data.entries !== 'object') return stringsToTranslate;

    Object.values(data.entries).forEach((entry: LorebookEntry) => {
      // Collect keys
      if (Array.isArray(entry.key)) {
        entry.key.forEach(k => {
          if (k && !VIETNAMESE_REGEX.test(k) && !k.includes('{{user}}') && !k.includes('{{char}}')) {
            stringsToTranslate.add(k);
          }
        });
      }
      // Collect secondary keys
      if (Array.isArray(entry.keysecondary)) {
        entry.keysecondary.forEach(k => {
          if (k && !VIETNAMESE_REGEX.test(k) && !k.includes('{{user}}') && !k.includes('{{char}}')) {
            stringsToTranslate.add(k);
          }
        });
      }
      // Collect comments
      if (typeof entry.comment === 'string' && entry.comment && !VIETNAMESE_REGEX.test(entry.comment)) {
        stringsToTranslate.add(entry.comment);
      }
    });
    return stringsToTranslate;
  };

  const runTranslationLoop = async (session: TranslationSession) => {
    setStatus(AppStatus.TRANSLATING);
    setErrorMsg(null);

    // Create a local mutable copy of results to accumulate during this run
    const currentResults = { ...session.results };
    let currentIndex = session.currentIndex;
    let localSkipped = 0;

    try {
      while (currentIndex < session.allStrings.length) {
        // Calculate current batch
        const batch = session.allStrings.slice(currentIndex, currentIndex + BATCH_SIZE);

        // Call API
        const batchResult = await translateBatch(batch, instructions);

        if (!batchResult) {
          // Failure: Skip this batch and continue
          console.warn(`Batch starting at index ${currentIndex} failed. Skipping.`);
          localSkipped++;
          setSkippedBatches(prev => prev + 1);
        } else {
          // Success: Update local results
          Object.assign(currentResults, batchResult);
        }

        // Move index regardless of success/failure
        currentIndex += BATCH_SIZE;

        // Update Progress
        const progressPercent = Math.min(100, Math.round((currentIndex / session.allStrings.length) * 100));
        setProgress(progressPercent);

        // Checkpoint state
        setTranslationSession({
          ...session,
          currentIndex: currentIndex,
          results: currentResults
        });
      }

      // Loop Finished
      applyTranslations(session.allStrings, currentResults);
      if (localSkipped > 0 || skippedBatches > 0) {
        setErrorMsg(`Completed with warnings: ${localSkipped + skippedBatches} batches were skipped due to API errors.`);
      }

    } catch (err: any) {
      console.error(err);
      setErrorMsg(err.message || "An unexpected error occurred.");
      setTranslationSession({
        ...session,
        currentIndex: currentIndex,
        results: currentResults
      });
      setStatus(AppStatus.PAUSED);
    }
  };

  const startTranslation = () => {
    if (!originalData) return;

    // 1. Extract strings
    const strings = extractStrings(originalData);
    if (strings.size === 0) {
      setStatus(AppStatus.SUCCESS);
      setTranslatedData(originalData);
      alert("No translatable content found (or all content appears to be Vietnamese already).");
      return;
    }

    const allStrings = Array.from(strings);

    // 2. Initialize Session
    const newSession: TranslationSession = {
      allStrings,
      currentIndex: 0,
      results: {},
      totalBatches: Math.ceil(allStrings.length / BATCH_SIZE)
    };

    setTranslationSession(newSession);
    setProgress(0);
    setSkippedBatches(0);

    // 3. Start Loop
    runTranslationLoop(newSession);
  };

  const resumeTranslation = () => {
    if (translationSession) {
      runTranslationLoop(translationSession);
    }
  };

  const applyTranslations = (allStrings: string[], results: Record<string, string>) => {
    if (!originalData) return;

    try {
      const workingData: Lorebook = JSON.parse(JSON.stringify(originalData));

      Object.values(workingData.entries).forEach((entry: LorebookEntry) => {
        if (Array.isArray(entry.key)) {
            const newKeys = entry.key
                .map(k => results[k])
                .filter((t): t is string => !!t && !entry.key.includes(t));
            entry.key.push(...newKeys);
        }
        if (Array.isArray(entry.keysecondary)) {
            const newKeys = entry.keysecondary
                .map(k => results[k])
                .filter((t): t is string => !!t && !entry.keysecondary.includes(t));
            entry.keysecondary.push(...newKeys);
        }
        if (typeof entry.comment === 'string' && results[entry.comment]) {
          entry.comment = results[entry.comment];
        }
      });

      setTranslatedData(workingData);
      setStatus(AppStatus.SUCCESS);
      setTranslationSession(null); // Clear session on success
    } catch (e) {
      console.error("Error applying translations:", e);
      setErrorMsg("Failed to apply translations to the JSON structure.");
      setStatus(AppStatus.ERROR);
    }
  };

  const handleDownload = () => {
    if (!translatedData || !file) return;

    const jsonString = JSON.stringify(translatedData, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);

    const a = document.createElement('a');
    a.href = url;
    const nameWithoutExt = file.name.replace(/\.json$/i, '');
    a.download = `${nameWithoutExt}_translated.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleCreativeGenerate = async () => {
    if (!translatedData || !selectedEntryUid || !creativePrompt.trim()) return;

    const entries = Object.values(translatedData.entries) as LorebookEntry[];
    const entry = entries.find(e => e.uid.toString() === selectedEntryUid);
    if (!entry) return;

    setIsCreativeLoading(true);
    setCreativeOutput('');

    const result = await generateCreativeContent(entry, creativePrompt);

    if (result) {
      setCreativeOutput(result);
    } else {
      setCreativeOutput("Failed to generate content. Please try again.");
    }
    setIsCreativeLoading(false);
  };

  const renderProgressBar = () => {
    if (!translationSession && status !== AppStatus.TRANSLATING) return null;

    const current = translationSession ? translationSession.currentIndex : 0;
    const total = translationSession ? translationSession.allStrings.length : 1;
    const currentBatchNum = Math.floor(current / BATCH_SIZE) + 1;
    const totalBatches = Math.ceil(total / BATCH_SIZE);

    return (
      <div className="w-full max-w-xl mx-auto mb-6">
        <div className="flex justify-between text-sm font-medium text-gray-700 mb-1">
          <span>
            {status === AppStatus.TRANSLATING ? 'Translating...' : 
             status === AppStatus.PAUSED ? 'Paused' : 'Processing'}
          </span>
          <span>{Math.round(progress)}% ({current}/{total} items)</span>
        </div>
        <div className="w-full bg-gray-200 rounded-full h-3 overflow-hidden">
          <div 
            className={`h-full transition-all duration-500 ease-out ${status === AppStatus.PAUSED ? 'bg-yellow-500' : 'bg-blue-600'}`}
            style={{ width: `${progress}%` }}
          ></div>
        </div>
        <div className="flex justify-between mt-2">
            <p className="text-xs text-gray-500">
            Processing batch {Math.min(currentBatchNum, totalBatches)} of {totalBatches}
            </p>
            {skippedBatches > 0 && (
                <p className="text-xs text-orange-500">
                    Skipped: {skippedBatches} batches
                </p>
            )}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen py-12 px-4 sm:px-6 lg:px-8 max-w-5xl mx-auto">
      <div className="text-center mb-10">
        <h1 className="text-4xl font-extrabold text-gray-900 tracking-tight">
          Lorebook Translator <span className="text-blue-600">with Gemini</span>
        </h1>
        <p className="mt-3 text-lg text-gray-600 max-w-2xl mx-auto">
          Translate and expand your character lorebooks effortlessly using AI.
        </p>
      </div>

      <div className="bg-white rounded-2xl shadow-xl overflow-hidden transition-all duration-300">
        <div className="p-8 space-y-8">

          {/* Section 1: Upload & Config */}
          <div className="border-b border-gray-100 pb-8 space-y-6">

            {/* File Upload */}
            <div className="flex flex-col sm:flex-row items-center justify-center gap-6">
              <input 
                type="file" 
                accept=".json" 
                ref={fileInputRef}
                onChange={handleFileChange} 
                className="hidden"
              />
              <Button 
                variant="secondary"
                onClick={() => fileInputRef.current?.click()}
                icon={<svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" /></svg>}
              >
                Select JSON File
              </Button>
              <span className={`text-lg font-medium ${file ? 'text-blue-600' : 'text-gray-400'}`}>
                {file ? file.name : 'No file selected'}
              </span>
            </div>

            {/* Instructions */}
            <div className="max-w-3xl mx-auto">
              <label htmlFor="instructions" className="block text-sm font-medium text-gray-700 mb-2">
                Additional Translation Instructions (Optional)
              </label>
              <textarea
                id="instructions"
                rows={3}
                className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-shadow bg-gray-50 text-gray-900"
                placeholder="e.g., Keep specific names in Pinyin, translate 'Sect' as 'Môn phái'..."
                value={instructions}
                onChange={(e) => setInstructions(e.target.value)}
              />
            </div>

            {/* Progress Bar Area */}
            {(status === AppStatus.TRANSLATING || status === AppStatus.PAUSED || translationSession) && renderProgressBar()}

            {/* Translate / Resume Button */}
            <div className="text-center">
              {status === AppStatus.PAUSED ? (
                 <Button 
