import { GoogleGenAI, Type } from "@google/genai";
import { LorebookEntry, ApiConfig } from "../types";

// Initialize Gemini Client
// The API key is obtained exclusively from the environment variable.
const geminiClient = new GoogleGenAI({ apiKey: process.env.API_KEY });

const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

/**
 * Helper to call Custom API (OpenAI Compatible)
 */
const callCustomApi = async (
  config: ApiConfig,
  messages: Array<{ role: string; content: string }>,
  jsonMode: boolean = false
): Promise<string> => {
  if (!config.baseUrl) throw new Error("API URL is required for custom provider");

  const headers: Record<string, string> = {
    'Content-Type': 'application/json',
  };
  if (config.apiKey) {
    headers['Authorization'] = `Bearer ${config.apiKey}`;
  }

  // Basic OpenAI compatible body
  const body: any = {
    model: config.model || 'gpt-3.5-turbo',
    messages: messages,
    temperature: 0.3, // Low temperature for translation accuracy
  };

  // Some providers require response_format for JSON, others default to text.
  // We'll rely on the prompt mainly, but can add this if widely supported.
  if (jsonMode && config.model?.includes('gpt')) {
     body.response_format = { type: "json_object" };
  }

  // Remove trailing slash from baseUrl if present and append /chat/completions
  const url = `${config.baseUrl.replace(/\/$/, '')}/chat/completions`;

  const response = await fetch(url, {
    method: 'POST',
    headers,
    body: JSON.stringify(body)
  });

  if (!response.ok) {
    let errText = await response.text();
    try {
        const errJson = JSON.parse(errText);
        if (errJson.error && errJson.error.message) errText = errJson.error.message;
    } catch (e) {}
    throw new Error(`Custom API Error ${response.status}: ${errText}`);
  }

  const data = await response.json();
  return data.choices?.[0]?.message?.content || "";
};

/**
 * Translates a batch of strings from Chinese to Vietnamese.
 */
export const translateBatch = async (
  strings: string[],
  instructions: string,
  apiConfig: ApiConfig,
  retries = 3
): Promise<Record<string, string> | null> => {
  const jsonKeywords = JSON.stringify(strings);

  let systemInstruction = `You are a translation assistant. Translate the following list of strings (mostly Chinese) into Vietnamese. 
  Your response MUST be ONLY a single, valid JSON object where keys are the original strings and values are their Vietnamese translations. 
  Do not include any other text, explanations, or markdown formatting like \`\`\`json.`;

  if (instructions) {
    systemInstruction += `\n\nFollow these specific user-provided rules for translation: "${instructions}".`;
  }

  const userMessage = `Strings to translate: ${jsonKeywords}`;

  for (let attempt = 0; attempt < retries; attempt++) {
    try {
      let textResponse = "";

      if (apiConfig.provider === 'custom') {
        textResponse = await callCustomApi(
          apiConfig, 
          [
            { role: "system", content: systemInstruction },
            { role: "user", content: userMessage }
          ],
          true
        );
      } else {
        // Default Gemini SDK
        const response = await geminiClient.models.generateContent({
          model: 'gemini-3-flash-preview', 
          contents: `${systemInstruction}\n\n${userMessage}`,
          config: {
            responseMimeType: 'application/json',
          }
        });
        textResponse = response.text || "";
      }

      if (!textResponse) throw new Error("Empty response received");

      // Clean up potential markdown code blocks
      const cleanedResponse = textResponse.replace(/^```json\s*/, '').replace(/```$/, '');
      return JSON.parse(cleanedResponse);

    } catch (error) {
      console.warn(`Translation attempt ${attempt + 1} failed:`, error);
      if (attempt === retries - 1) {
        console.error("All translation attempts failed.");
        return null;
      }
      await wait(1000 * Math.pow(2, attempt));
    }
  }
  return null;
};

/**
 * Generates creative content based on a lorebook entry.
 */
export const generateCreativeContent = async (
  entry: LorebookEntry,
  userPrompt: string,
  apiConfig: ApiConfig
): Promise<string | null> => {
  const systemPrompt = `You are a creative writing assistant. Based on the lorebook entry provided below, please fulfill the user's request in detail and in an engaging style.`;

  const contentPrompt = `**Lorebook Entry:**
- **Title/Comment:** ${entry.comment || 'N/A'}
- **Keywords:** ${entry.key ? entry.key.join(', ') : 'N/A'}
- **Content:**
${entry.content}

**User Request:**
${userPrompt}`;

  try {
    if (apiConfig.provider === 'custom') {
        return await callCustomApi(
            apiConfig,
            [
                { role: "system", content: systemPrompt },
                { role: "user", content: contentPrompt }
            ]
        );
    } else {
        // Default Gemini SDK
        const response = await geminiClient.models.generateContent({
        model: 'gemini-3-pro-preview', 
        contents: `${systemPrompt}\n\n${contentPrompt}`,
        });
        return response.text || null;
    }
  } catch (error) {
    console.error("Creative API Error:", error);
    return null;
  }
};

import React, { useState, useRef } from 'react';
import { translateBatch, generateCreativeContent } from './services/geminiService';
import { Lorebook, LorebookEntry, AppStatus, TranslationSession, ApiProvider, ApiConfig } from './types';
import { Spinner } from './components/Spinner';
import { Button } from './components/Button';

// Regex to identify Vietnamese characters (to skip already translated items)
const VIETNAMESE_REGEX = /[àáạảãâầấậẩẫăằắặẳẵèéẹẻẽêềếệểễìíịỉĩòóọỏõôồốộổỗơờớợởỡùúụủũưừứựửữỳýỵỷỹđ]/i;

const BATCH_SIZE = 50;

const App: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [originalData, setOriginalData] = useState<Lorebook | null>(null);
  const [translatedData, setTranslatedData] = useState<Lorebook | null>(null);
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [instructions, setInstructions] = useState<string>('');
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // API Configuration State
  const [apiProvider, setApiProvider] = useState<ApiProvider>('gemini');
  const [customApiUrl, setCustomApiUrl] = useState<string>('');
  const [customApiKey, setCustomApiKey] = useState<string>('');
  const [customModels, setCustomModels] = useState<string[]>([]);
  const [selectedCustomModel, setSelectedCustomModel] = useState<string>('');
  const [isApiConnected, setIsApiConnected] = useState<boolean>(false);
  const [isConnecting, setIsConnecting] = useState<boolean>(false);

  // Translation Session State (for progress & resume)
  const [translationSession, setTranslationSession] = useState<TranslationSession | null>(null);
  const [progress, setProgress] = useState<number>(0);
  const [skippedBatches, setSkippedBatches] = useState<number>(0);

  // Creative Assistant State
  const [selectedEntryUid, setSelectedEntryUid] = useState<string>('');
  const [creativePrompt, setCreativePrompt] = useState<string>('');
  const [creativeOutput, setCreativeOutput] = useState<string>('');
  const [isCreativeLoading, setIsCreativeLoading] = useState<boolean>(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleConnectApi = async () => {
    if (!customApiUrl) {
      setErrorMsg("Please enter an API URL.");
      return;
    }

    setIsConnecting(true);
    setErrorMsg(null);

    try {
      const url = customApiUrl.replace(/\/$/, '') + '/models';
      const headers: Record<string, string> = {
        'Content-Type': 'application/json'
      };
      if (customApiKey) {
        headers['Authorization'] = `Bearer ${customApiKey}`;
      }

      const res = await fetch(url, { headers });
      if (!res.ok) throw new Error('Failed to connect to API');

      const data = await res.json();
      const modelsData = data.data || data.models || [];

      // Extract model IDs
      const modelIds: string[] = modelsData.map((m: any) => 
        typeof m === 'string' ? m : (m.id || m.name)
      );

      if (modelIds.length === 0) throw new Error('No models found in API response');

      setCustomModels(modelIds);
      setSelectedCustomModel(modelIds[0]);
      setIsApiConnected(true);
    } catch (err: any) {
      console.error(err);
      setErrorMsg(`Connection failed: ${err.message}`);
      setIsApiConnected(false);
    } finally {
      setIsConnecting(false);
    }
  };

  const getApiConfig = (): ApiConfig => {
    return {
      provider: apiProvider,
      baseUrl: customApiUrl,
      apiKey: customApiKey,
      model: selectedCustomModel
    };
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const selectedFile = e.target.files[0];
      setFile(selectedFile);
      setErrorMsg(null);

      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const content = event.target?.result as string;
          const json = JSON.parse(content);
          setOriginalData(json);
          // Reset previous results
          setTranslatedData(null);
          setTranslationSession(null);
          setProgress(0);
          setSkippedBatches(0);
          setStatus(AppStatus.IDLE);
        } catch (err) {
          setErrorMsg("Invalid JSON file format.");
          setFile(null);
        }
      };
      reader.readAsText(selectedFile);
    }
  };

  const extractStrings = (data: Lorebook): Set<string> => {
    const stringsToTranslate = new Set<string>();
    if (!data.entries || typeof data.entries !== 'object') return stringsToTranslate;

    Object.values(data.entries).forEach((entry: LorebookEntry) => {
      // Collect keys
      if (Array.isArray(entry.key)) {
        entry.key.forEach(k => {
          if (k && !VIETNAMESE_REGEX.test(k) && !k.includes('{{user}}') && !k.includes('{{char}}')) {
            stringsToTranslate.add(k);
          }
        });
      }
      // Collect secondary keys
      if (Array.isArray(entry.keysecondary)) {
        entry.keysecondary.forEach(k => {
          if (k && !VIETNAMESE_REGEX.test(k) && !k.includes('{{user}}') && !k.includes('{{char}}')) {
            stringsToTranslate.add(k);
          }
        });
      }
      // Collect comments
      if (typeof entry.comment === 'string' && entry.comment && !VIETNAMESE_REGEX.test(entry.comment)) {
        stringsToTranslate.add(entry.comment);
      }
    });
    return stringsToTranslate;
  };

  const runTranslationLoop = async (session: TranslationSession) => {
    setStatus(AppStatus.TRANSLATING);
    setErrorMsg(null);

    const apiConfig = getApiConfig();

    // Create a local mutable copy of results to accumulate during this run
    const currentResults = { ...session.results };
    let currentIndex = session.currentIndex;
    let localSkipped = 0;

    try {
      while (currentIndex < session.allStrings.length) {
        // Calculate current batch
        const batch = session.allStrings.slice(currentIndex, currentIndex + BATCH_SIZE);

        // Call API
        const batchResult = await translateBatch(batch, instructions, apiConfig);

        if (!batchResult) {
          // Failure: Skip this batch and continue
          console.warn(`Batch starting at index ${currentIndex} failed. Skipping.`);
          localSkipped++;
          setSkippedBatches(prev => prev + 1);
        } else {
          // Success: Update local results
          Object.assign(currentResults, batchResult);
        }

        // Move index regardless of success/failure
        currentIndex += BATCH_SIZE;

        // Update Progress
        const progressPercent = Math.min(100, Math.round((currentIndex / session.allStrings.length) * 100));
        setProgress(progressPercent);

        // Checkpoint state
        setTranslationSession({
          ...session,
          currentIndex: currentIndex,
          results: currentResults
        });
      }

      // Loop Finished
      applyTranslations(session.allStrings, currentResults);
      if (localSkipped > 0 || skippedBatches > 0) {
        setErrorMsg(`Completed with warnings: ${localSkipped + skippedBatches} batches were skipped due to API errors.`);
      }

    } catch (err: any) {
      console.error(err);
      setErrorMsg(err.message || "An unexpected error occurred.");
      setTranslationSession({
        ...session,
        currentIndex: currentIndex,
        results: currentResults
      });
      setStatus(AppStatus.PAUSED);
    }
  };

  const startTranslation = () => {
    if (!originalData) return;
    if (apiProvider === 'custom' && !isApiConnected) {
        setErrorMsg("Please connect to your Custom API first.");
        return;
    }

    // 1. Extract strings
    const strings = extractStrings(originalData);
    if (strings.size === 0) {
      setStatus(AppStatus.SUCCESS);
      setTranslatedData(originalData);
      alert("No translatable content found (or all content appears to be Vietnamese already).");
      return;
    }

    const allStrings = Array.from(strings);

    // 2. Initialize Session
    const newSession: TranslationSession = {
      allStrings,
      currentIndex: 0,
      results: {},
      totalBatches: Math.ceil(allStrings.length / BATCH_SIZE)
    };

    setTranslationSession(newSession);
    setProgress(0);
    setSkippedBatches(0);

    // 3. Start Loop
    runTranslationLoop(newSession);
  };

  const resumeTranslation = () => {
    if (translationSession) {
      runTranslationLoop(translationSession);
    }
  };

  const applyTranslations = (allStrings: string[], results: Record<string, string>) => {
    if (!originalData) return;

    try {
      const workingData: Lorebook = JSON.parse(JSON.stringify(originalData));

      Object.values(workingData.entries).forEach((entry: LorebookEntry) => {
        if (Array.isArray(entry.key)) {
            const newKeys = entry.key
                .map(k => results[k])
                .filter((t): t is string => !!t && !entry.key.includes(t));
            entry.key.push(...newKeys);
        }
        if (Array.isArray(entry.keysecondary)) {
            const newKeys = entry.keysecondary
                .map(k => results[k])
                .filter((t): t is string => !!t && !entry.keysecondary.includes(t));
            entry.keysecondary.push(...newKeys);
        }
        if (typeof entry.comment === 'string' && results[entry.comment]) {
          entry.comment = results[entry.comment];
        }
      });

      setTranslatedData(workingData);
      setStatus(AppStatus.SUCCESS);
      setTranslationSession(null); // Clear session on success
    } catch (e) {
      console.error("Error applying translations:", e);
      setErrorMsg("Failed to apply translations to the JSON structure.");
      setStatus(AppStatus.ERROR);
    }
  };

  const handleDownload = () => {
    if (!translatedData || !file) return;

    const jsonString = JSON.stringify(translatedData, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);

    const a = document.createElement('a');
    a.href = url;
    const nameWithoutExt = file.name.replace(/\.json$/i, '');
    a.download = `${nameWithoutExt}_translated.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleCreativeGenerate = async () => {
    if (!translatedData || !selectedEntryUid || !creativePrompt.trim()) return;
    if (apiProvider === 'custom' && !isApiConnected) {
        setErrorMsg("Please connect to your Custom API first.");
        return;
    }

    const entries = Object.values(translatedData.entries) as LorebookEntry[];
    const entry = entries.find(e => e.uid.toString() === selectedEntryUid);
    if (!entry) return;

    setIsCreativeLoading(true);
    setCreativeOutput('');

    const apiConfig = getApiConfig();
    const result = await generateCreativeContent(entry, creativePrompt, apiConfig);

    if (result) {
      setCreativeOutput(result);
    } else {
      setCreativeOutput("Failed to generate content. Please try again.");
    }
    setIsCreativeLoading(false);
  };

  const renderProgressBar = () => {
    if (!translationSession && status !== AppStatus.TRANSLATING) return null;

    const current = translationSession ? translationSession.currentIndex : 0;
    const total = translationSession ? translationSession.allStrings.length : 1;
    const currentBatchNum = Math.floor(current / BATCH_SIZE) + 1;
    const totalBatches = Math.ceil(total / BATCH_SIZE);

    return (
      <div className="w-full max-w-xl mx-auto mb-6">
        <div className="flex justify-between text-sm font-medium text-gray-700 mb-1">
          <span>
            {status === AppStatus.TRANSLATING ? 'Translating...' : 
             status === AppStatus.PAUSED ? 'Paused' : 'Processing'}
          </span>
          <span>{Math.round(progress)}% ({current}/{total} items)</span>
        </div>
        <div className="w-full bg-gray-200 rounded-full h-3 overflow-hidden">
          <div 
            className={`h-full transition-all duration-500 ease-out ${status === AppStatus.PAUSED ? 'bg-yellow-500' : 'bg-blue-600'}`}
            style={{ width: `${progress}%` }}
          ></div>
        </div>
        <div className="flex justify-between mt-2">
            <p className="text-xs text-gray-500">
            Processing batch {Math.min(currentBatchNum, totalBatches)} of {totalBatches}
            </p>
            {skippedBatches > 0 && (
                <p className="text-xs text-orange-500">
                    Skipped: {skippedBatches} batches
                </p>
            )}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen py-12 px-4 sm:px-6 lg:px-8 max-w-5xl mx-auto">
      <div className="text-center mb-10">
        <h1 className="text-4xl font-extrabold text-gray-900 tracking-tight">
          Lorebook Translator <span className="text-blue-600">with Gemini</span>
        </h1>
        <p className="mt-3 text-lg text-gray-600 max-w-2xl mx-auto">
          Translate and expand your character lorebooks effortlessly using AI.
        </p>
      </div>

      <div className="bg-white rounded-2xl shadow-xl overflow-hidden transition-all duration-300">
        <div className="p-8 space-y-8">

          {/* Section 1: Upload & Config */}
          <div className="border-b border-gray-100 pb-8 space-y-6">

            {/* API Settings */}
            <div className="bg-gray-50 p-6 rounded-xl border border-gray-200">
              <h3 className="text-lg font-semibold text-gray-800 mb-4 flex items-center gap-2">
                <svg className="w-5 h-5 text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                API Configuration
              </h3>

              <div className="flex gap-4 mb-4">
                <button 
                  onClick={() => setApiProvider('gemini')}
                  className={`flex-1 py-2 px-4 rounded-lg font-medium transition-colors ${apiProvider === 'gemini' ? 'bg-blue-600 text-white' : 'bg-white text-gray-700 border border-gray-300 hover:bg-gray-100'}`}
                >
                  Google Gemini (Default)
                </button>
                <button 
                  onClick={() => setApiProvider('custom')}
                  className={`flex-1 py-2 px-4 rounded-lg font-medium transition-colors ${apiProvider === 'custom' ? 'bg-blue-600 text-white' : 'bg-white text-gray-700 border border-gray-300 hover:bg-gray-100'}`}
                >
                  Custom API (OpenAI Compatible)
                </button>
              </div>

              {apiProvider === 'custom' && (
                <div className="space-y-4 animate-fade-in">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">API URL</label>
                      <input 
                        type="text" 
                        value={customApiUrl}
                        onChange={(e) => setCustomApiUrl(e.target.value)}
                        placeholder="https://api.openai.com/v1"
                        className="w-full p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">API Key</label>
                      <input 
                        type="password" 
                        value={customApiKey}
                        onChange={(e) => setCustomApiKey(e.target.value)}
                        placeholder="sk-..."
                        className="w-full p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                      />
                    </div>
                  </div>

                  <div className="flex items-end gap-4">
                    <div className="flex-1">
                      <label className="block text-sm font-medium text-gray-700 mb-1">Select Model</label>
                      <select 
                        disabled={!isApiConnected || customModels.length === 0}
                        value={selectedCustomModel}
                        onChange={(e) => setSelectedCustomModel(e.target.value)}
                        className="w-full p-2 border border-gray-300 rounded-lg bg-white disabled:bg-gray-100 disabled:text-gray-400"
                      >
                         {customModels.length === 0 && <option>Connect to fetch models</option>}
                         {customModels.map(m => <option key={m} value={m}>{m}</option>)}
                      </select>
                    </div>
                    <Button 
                      onClick={handleConnectApi} 
                      disabled={isConnecting || !customApiUrl}
                      className="h-[42px] min-w-[120px]"
                      variant={isApiConnected ? "secondary" : "primary"}
                    >
                      {isConnecting ? <Spinner /> : isApiConnected ? "Connected" : "Connect"}
                    </Button>
                  </div>
                </div>
              )}
            </div>

            {/* File Upload */}
            <div className="flex flex-col sm:flex-row items-center justify-center gap-6">
              <input 
                type="file" 
                accept=".json" 
                ref={fileInputRef}
                onChange={handleFileChange} 
                className="hidden"
              />
              <Button 
                variant="secondary"
                onClick={() => fileInputRef.current?.click()}
                icon={<svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" /></svg>}
              >
                Select JSON File
              </Button>
              <span className={`text-lg font-medium ${file ? 'text-blue-600' : 'text-gray-400'}`}>
                {file ? file.name : 'No file selected'}
              </span>
            </div>

            {/* Instructions */}
            <div className="max-w-3xl mx-auto">
              <label htmlFor="instructions" className="block text-sm font-medium text-gray-700 mb-2">
                Additional Translation Instructions (Optional)
              </label>
              <textarea
                id="instructions"
                rows={3}
                className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-shadow bg-gray-50 text-gray-900"
                placeholder="e.g., Keep specific names in Pinyin, translate 'Sect' as 'Môn phái'..."
                value={instructions}
                onChange={(e) => setInstructions(e.target.value)}
              />
            </div>

            {/* Progress Bar Area */}
            {(status === AppStatus.TRANSLATING || status === AppStatus.PAUSED || translationSession) && renderProgressBar()}

            {/* Translate / Resume Button */}
            <div className="text-center">
              {status === AppStatus.PAUSED ? (
                 <Button 
                  onClick={resumeTranslation}
                  className="w-full sm:w-auto min-w-[200px] bg-yellow-600 hover:bg-yellow-700"
                  icon={<svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>}
                >
                  Resume Translation
                </Button>
              ) : (
                <Button 
                  onClick={startTranslation}
                  disabled={!file || status === AppStatus.TRANSLATING}
                  className="w-full sm:w-auto min-w-[200px]"
                  icon={status === AppStatus.TRANSLATING ? <Spinner /> : <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 5h12M9 3v2m1.048 9.5A18.022 18.022 0 016.412 9m6.088 9h7M11 21l5-10 5 10M12.751 5C11.783 10.77 8.07 15.61 3 18.129" /></svg>}
                >
                  {status === AppStatus.TRANSLATING ? ' Translating...' : `Translate with ${apiProvider === 'gemini' ? 'Gemini' : 'Custom API'}`}
                </Button>
              )}
            </div>

            {errorMsg && (
               <div className={`border-l-4 p-4 rounded-md max-w-3xl mx-auto ${status === AppStatus.SUCCESS ? 'bg-orange-50 border-orange-500' : 'bg-red-50 border-red-500'}`}>
                 <p className={status === AppStatus.SUCCESS ? 'text-orange-700' : 'text-red-700'}>{errorMsg}</p>
               </div>
            )}
          </div>

          {/* Section 2: Results & Creative */}
          {(status === AppStatus.SUCCESS && translatedData) && (
            <div className="space-y-8 animate-fade-in">
              <div className="flex flex-col sm:flex-row items-center justify-between bg-green-50 p-6 rounded-xl border border-green-100">
                <div className="mb-4 sm:mb-0">
                  <h2 className="text-2xl font-bold text-green-800">Translation Complete!</h2>
                  <p className="text-green-600">Your lorebook has been processed successfully.</p>
                </div>
                <Button variant="secondary" onClick={handleDownload} icon={<svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>}>
                  Download JSON
                </Button>
              </div>

              {/* Preview Box */}
              <div className="bg-gray-900 rounded-xl overflow-hidden shadow-inner">
                <div className="bg-gray-800 px-4 py-2 text-xs text-gray-400 font-mono uppercase tracking-wider flex justify-between">
                  <span>Preview (First 50 lines)</span>
                </div>
                <pre className="p-4 text-green-400 font-mono text-sm h-64 overflow-y-auto custom-scrollbar">
                  {JSON.stringify(translatedData, null, 2).slice(0, 5000) + (JSON.stringify(translatedData).length > 5000 ? '...' : '')}
                </pre>
              </div>

              {/* Creative Assistant */}
              <div className="bg-blue-50 border border-blue-100 rounded-xl p-6 sm:p-8">
                <div className="text-center mb-6">
                  <h2 className="text-2xl font-bold text-blue-900 flex items-center justify-center gap-2">
                    <svg className="w-6 h-6 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                    Creative Assistant
                  </h2>
                  <p className="text-blue-700">Expand your lore using the context of your translated entries.</p>
                </div>

                <div className="grid gap-6">
                  <div>
                    <label className="block text-sm font-medium text-blue-900 mb-2">Select Lorebook Entry</label>
                    <select 
                      className="w-full p-3 border border-blue-200 rounded-lg bg-white focus:ring-2 focus:ring-blue-500 outline-none text-gray-700"
                      value={selectedEntryUid}
                      onChange={(e) => setSelectedEntryUid(e.target.value)}
                    >
                      <option value="">-- Choose an entry --</option>
                      {(Object.values(translatedData.entries) as LorebookEntry[]).map((entry) => (
                        <option key={entry.uid} value={entry.uid}>
                          {entry.comment || (entry.key && entry.key[0]) || `Entry ${entry.uid}`}
                        </option>
                      ))}
                    </select>
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-blue-900 mb-2">Your Creative Prompt</label>
                    <textarea 
                      rows={3}
                      className="w-full p-3 border border-blue-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-gray-900"
                      placeholder="e.g., Write a short backstory for this character involving a lost artifact..."
                      value={creativePrompt}
                      onChange={(e) => setCreativePrompt(e.target.value)}
                    />
                  </div>

                  <div className="text-center">
                    <Button 
                      onClick={handleCreativeGenerate} 
                      disabled={isCreativeLoading || !selectedEntryUid || !creativePrompt}
                      className="w-full sm:w-auto"
                      variant="primary"
                    >
                      {isCreativeLoading ? (
                        <span className="flex items-center gap-2">
                          <Spinner /> Generative Magic...
                        </span>
                      ) : (
                        <span className="flex items-center gap-2">
                          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.428 15.428a2 2 0 00-1.022-.547l-2.384-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z" /></svg>
                          Generate Content
                        </span>
                      )}
                    </Button>
                  </div>

                  {creativeOutput && (
                    <div className="mt-6 bg-white rounded-lg p-6 border border-blue-100 shadow-sm">
                      <h3 className="text-lg font-bold text-gray-800 mb-3">Result:</h3>
                      <div className="prose prose-blue max-w-none text-gray-700 whitespace-pre-wrap leading-relaxed">
                        {creativeOutput}
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { translateBatch, generateCreativeContent } from './services/geminiService';
import { Lorebook, LorebookEntry, AppStatus, TranslationSession, ApiProvider, ApiConfig } from './types';
import { Spinner } from './components/Spinner';
import { Button } from './components/Button';

// Regex to identify Vietnamese characters (to skip already translated items)
const VIETNAMESE_REGEX = /[àáạảãâầấậẩẫăằắặẳẵèéẹẻẽêềếệểễìíịỉĩòóọỏõôồốộổỗơờớợởỡùúụủũưừứựửữỳýỵỷỹđ]/i;

const BATCH_SIZE = 50;

const App: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [originalData, setOriginalData] = useState<Lorebook | null>(null);
  const [translatedData, setTranslatedData] = useState<Lorebook | null>(null);
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [instructions, setInstructions] = useState<string>('');
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // API Configuration State
  const [apiProvider, setApiProvider] = useState<ApiProvider>('gemini');
  const [customApiUrl, setCustomApiUrl] = useState<string>('');
  const [customApiKey, setCustomApiKey] = useState<string>('');
  const [customModels, setCustomModels] = useState<string[]>([]);
  const [selectedCustomModel, setSelectedCustomModel] = useState<string>('');
  const [isApiConnected, setIsApiConnected] = useState<boolean>(false);
  const [isConnecting, setIsConnecting] = useState<boolean>(false);

  // Translation Session State (for progress & resume)
  const [translationSession, setTranslationSession] = useState<TranslationSession | null>(null);
  const [progress, setProgress] = useState<number>(0);
  const [skippedBatches, setSkippedBatches] = useState<number>(0);

  // Creative Assistant State
  const [selectedEntryUid, setSelectedEntryUid] = useState<string>('');
  const [creativePrompt, setCreativePrompt] = useState<string>('');
  const [creativeOutput, setCreativeOutput] = useState<string>('');
  const [isCreativeLoading, setIsCreativeLoading] = useState<boolean>(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleConnectApi = async () => {
    if (!customApiUrl) {
      setErrorMsg("Please enter an API URL.");
      return;
    }

    setIsConnecting(true);
    setErrorMsg(null);

    try {
      const url = customApiUrl.replace(/\/$/, '') + '/models';
      const headers: Record<string, string> = {
        'Content-Type': 'application/json'
      };
      if (customApiKey) {
        headers['Authorization'] = `Bearer ${customApiKey}`;
      }

      const res = await fetch(url, { headers });
      if (!res.ok) throw new Error('Failed to connect to API');

      const data = await res.json();
      const modelsData = data.data || data.models || [];

      // Extract model IDs
      const modelIds: string[] = modelsData.map((m: any) => 
        typeof m === 'string' ? m : (m.id || m.name)
      );

      if (modelIds.length === 0) throw new Error('No models found in API response');

      setCustomModels(modelIds);
      setSelectedCustomModel(modelIds[0]);
      setIsApiConnected(true);
    } catch (err: any) {
      console.error(err);
      setErrorMsg(`Connection failed: ${err.message}`);
      setIsApiConnected(false);
    } finally {
      setIsConnecting(false);
    }
  };

  const getApiConfig = (): ApiConfig => {
    return {
      provider: apiProvider,
      baseUrl: customApiUrl,
      apiKey: customApiKey,
      model: selectedCustomModel
    };
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const selectedFile = e.target.files[0];
      setFile(selectedFile);
      setErrorMsg(null);

      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const content = event.target?.result as string;
          const json = JSON.parse(content);
          setOriginalData(json);
          // Reset previous results
          setTranslatedData(null);
          setTranslationSession(null);
          setProgress(0);
          setSkippedBatches(0);
          setStatus(AppStatus.IDLE);
        } catch (err) {
          setErrorMsg("Invalid JSON file format.");
          setFile(null);
        }
      };
      reader.readAsText(selectedFile);
    }
  };

  const extractStrings = (data: Lorebook): Set<string> => {
    const stringsToTranslate = new Set<string>();
    if (!data.entries || typeof data.entries !== 'object') return stringsToTranslate;

    Object.values(data.entries).forEach((entry: LorebookEntry) => {
      // Collect keys
      if (Array.isArray(entry.key)) {
        entry.key.forEach(k => {
          if (k && !VIETNAMESE_REGEX.test(k) && !k.includes('{{user}}') && !k.includes('{{char}}')) {
            stringsToTranslate.add(k);
          }
        });
      }
      // Collect secondary keys
      if (Array.isArray(entry.keysecondary)) {
        entry.keysecondary.forEach(k => {
          if (k && !VIETNAMESE_REGEX.test(k) && !k.includes('{{user}}') && !k.includes('{{char}}')) {
            stringsToTranslate.add(k);
          }
        });
      }
      // Collect comments
      if (typeof entry.comment === 'string' && entry.comment && !VIETNAMESE_REGEX.test(entry.comment)) {
        stringsToTranslate.add(entry.comment);
      }
    });
    return stringsToTranslate;
  };

  const runTranslationLoop = async (session: TranslationSession) => {
    setStatus(AppStatus.TRANSLATING);
    setErrorMsg(null);

    const apiConfig = getApiConfig();

    // Create a local mutable copy of results to accumulate during this run
    const currentResults = { ...session.results };
    let currentIndex = session.currentIndex;
    let localSkipped = 0;

    try {
      while (currentIndex < session.allStrings.length) {
        // Calculate current batch
        const batch = session.allStrings.slice(currentIndex, currentIndex + BATCH_SIZE);

        // Call API
        const batchResult = await translateBatch(batch, instructions, apiConfig);

        if (!batchResult) {
          // Failure: Skip this batch and continue
          console.warn(`Batch starting at index ${currentIndex} failed. Skipping.`);
          localSkipped++;
          setSkippedBatches(prev => prev + 1);
        } else {
          // Success: Update local results
          Object.assign(currentResults, batchResult);
        }

        // Move index regardless of success/failure
        currentIndex += BATCH_SIZE;

        // Update Progress
        const progressPercent = Math.min(100, Math.round((currentIndex / session.allStrings.length) * 100));
        setProgress(progressPercent);

        // Checkpoint state
        setTranslationSession({
          ...session,
          currentIndex: currentIndex,
          results: currentResults
        });
      }

      // Loop Finished
      applyTranslations(session.allStrings, currentResults);
      if (localSkipped > 0 || skippedBatches > 0) {
        setErrorMsg(`Completed with warnings: ${localSkipped + skippedBatches} batches were skipped due to API errors.`);
      }

    } catch (err: any) {
      console.error(err);
      setErrorMsg(err.message || "An unexpected error occurred.");
      setTranslationSession({
        ...session,
        currentIndex: currentIndex,
        results: currentResults
      });
      setStatus(AppStatus.PAUSED);
    }
  };

  const startTranslation = () => {
    if (!originalData) return;
    if (apiProvider === 'custom' && !isApiConnected) {
        setErrorMsg("Please connect to your Custom API first.");
        return;
    }

    // 1. Extract strings
    const strings = extractStrings(originalData);
    if (strings.size === 0) {
      setStatus(AppStatus.SUCCESS);
      setTranslatedData(originalData);
      alert("No translatable content found (or all content appears to be Vietnamese already).");
      return;
    }

    const allStrings = Array.from(strings);

    // 2. Initialize Session
    const newSession: TranslationSession = {
      allStrings,
      currentIndex: 0,
      results: {},
      totalBatches: Math.ceil(allStrings.length / BATCH_SIZE)
    };

    setTranslationSession(newSession);
    setProgress(0);
    setSkippedBatches(0);

    // 3. Start Loop
    runTranslationLoop(newSession);
  };

  const resumeTranslation = () => {
    if (translationSession) {
      runTranslationLoop(translationSession);
    }
  };

  const applyTranslations = (allStrings: string[], results: Record<string, string>) => {
    if (!originalData) return;

    try {
      const workingData: Lorebook = JSON.parse(JSON.stringify(originalData));

      Object.values(workingData.entries).forEach((entry: LorebookEntry) => {
        if (Array.isArray(entry.key)) {
            const newKeys = entry.key
                .map(k => results[k])
                .filter((t): t is string => !!t && !entry.key.includes(t));
            entry.key.push(...newKeys);
        }
        if (Array.isArray(entry.keysecondary)) {
            const newKeys = entry.keysecondary
                .map(k => results[k])
                .filter((t): t is string => !!t && !entry.keysecondary.includes(t));
            entry.keysecondary.push(...newKeys);
        }
        if (typeof entry.comment === 'string' && results[entry.comment]) {
          entry.comment = results[entry.comment];
        }
      });

      setTranslatedData(workingData);
      setStatus(AppStatus.SUCCESS);
      setTranslationSession(null); // Clear session on success
    } catch (e) {
      console.error("Error applying translations:", e);
      setErrorMsg("Failed to apply translations to the JSON structure.");
      setStatus(AppStatus.ERROR);
    }
  };

  const handleDownload = () => {
    if (!translatedData || !file) return;

    const jsonString = JSON.stringify(translatedData, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);

    const a = document.createElement('a');
    a.href = url;
    const nameWithoutExt = file.name.replace(/\.json$/i, '');
    a.download = `${nameWithoutExt}_translated.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleCreativeGenerate = async () => {
    if (!translatedData || !selectedEntryUid || !creativePrompt.trim()) return;
    if (apiProvider === 'custom' && !isApiConnected) {
        setErrorMsg("Please connect to your Custom API first.");
        return;
    }

    const entries = Object.values(translatedData.entries) as LorebookEntry[];
    const entry = entries.find(e => e.uid.toString() === selectedEntryUid);
    if (!entry) return;

    setIsCreativeLoading(true);
    setCreativeOutput('');

    const apiConfig = getApiConfig();
    const result = await generateCreativeContent(entry, creativePrompt, apiConfig);

    if (result) {
      setCreativeOutput(result);
    } else {
      setCreativeOutput("Failed to generate content. Please try again.");
    }
    setIsCreativeLoading(false);
  };

  const renderProgressBar = () => {
    if (!translationSession && status !== AppStatus.TRANSLATING) return null;

    const current = translationSession ? translationSession.currentIndex : 0;
    const total = translationSession ? translationSession.allStrings.length : 1;
    const currentBatchNum = Math.floor(current / BATCH_SIZE) + 1;
    const totalBatches = Math.ceil(total / BATCH_SIZE);

    return (
      <div className="w-full max-w-xl mx-auto mb-6">
        <div className="flex justify-between text-sm font-medium text-gray-700 mb-1">
          <span>
            {status === AppStatus.TRANSLATING ? 'Translating...' : 
             status === AppStatus.PAUSED ? 'Paused' : 'Processing'}
          </span>
          <span>{Math.round(progress)}% ({current}/{total} items)</span>
        </div>
        <div className="w-full bg-gray-200 rounded-full h-3 overflow-hidden">
          <div 
            className={`h-full transition-all duration-500 ease-out ${status === AppStatus.PAUSED ? 'bg-yellow-500' : 'bg-blue-600'}`}
            style={{ width: `${progress}%` }}
          ></div>
        </div>
        <div className="flex justify-between mt-2">
            <p className="text-xs text-gray-500">
            Processing batch {Math.min(currentBatchNum, totalBatches)} of {totalBatches}
            </p>
            {skippedBatches > 0 && (
                <p className="text-xs text-orange-500">
                    Skipped: {skippedBatches} batches
                </p>
            )}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen py-12 px-4 sm:px-6 lg:px-8 max-w-5xl mx-auto">
      <div className="text-center mb-10">
        <h1 className="text-4xl font-extrabold text-gray-900 tracking-tight">
          Lorebook Translator <span className="text-blue-600">with Gemini</span>
        </h1>
        <p className="mt-3 text-lg text-gray-600 max-w-2xl mx-auto">
          Translate and expand your character lorebooks effortlessly using AI.
        </p>
      </div>

      <div className="bg-white rounded-2xl shadow-xl overflow-hidden transition-all duration-300">
        <div className="p-8 space-y-8">

          {/* Section 1: Upload & Config */}
          <div className="border-b border-gray-100 pb-8 space-y-6">

            {/* API Settings */}
            <div className="bg-gray-50 p-6 rounded-xl border border-gray-200">
              <h3 className="text-lg font-semibold text-gray-800 mb-4 flex items-center gap-2">
                <svg className="w-5 h-5 text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                API Configuration
              </h3>

              <div className="flex gap-4 mb-4">
                <button 
                  onClick={() => setApiProvider('gemini')}
                  className={`flex-1 py-2 px-4 rounded-lg font-medium transition-colors ${apiProvider === 'gemini' ? 'bg-blue-600 text-white' : 'bg-white text-gray-700 border border-gray-300 hover:bg-gray-100'}`}
                >
                  Google Gemini (Default)
                </button>
                <button 
                  onClick={() => setApiProvider('custom')}
                  className={`flex-1 py-2 px-4 rounded-lg font-medium transition-colors ${apiProvider === 'custom' ? 'bg-blue-600 text-white' : 'bg-white text-gray-700 border border-gray-300 hover:bg-gray-100'}`}
                >
                  Custom API (OpenAI Compatible)
                </button>
              </div>

              {apiProvider === 'custom' && (
                <div className="space-y-4 animate-fade-in">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">API URL</label>
                      <input 
                        type="text" 
                        value={customApiUrl}
                        onChange={(e) => setCustomApiUrl(e.target.value)}
                        placeholder="https://api.openai.com/v1"
                        className="w-full p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-gray-900"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">API Key</label>
                      <input 
                        type="password" 
                        value={customApiKey}
                        onChange={(e) => setCustomApiKey(e.target.value)}
                        placeholder="sk-..."
                        className="w-full p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-gray-900"
                      />
                    </div>
                  </div>

                  <div className="flex items-end gap-4">
                    <div className="flex-1">
                      <label className="block text-sm font-medium text-gray-700 mb-1">Select Model</label>
                      <select 
                        disabled={!isApiConnected || customModels.length === 0}
                        value={selectedCustomModel}
                        onChange={(e) => setSelectedCustomModel(e.target.value)}
                        className="w-full p-2 border border-gray-300 rounded-lg bg-white disabled:bg-gray-100 disabled:text-gray-400 text-gray-900"
                      >
                         {customModels.length === 0 && <option>Connect to fetch models</option>}
                         {customModels.map(m => <option key={m} value={m}>{m}</option>)}
                      </select>
                    </div>
                    <Button 
                      onClick={handleConnectApi} 
                      disabled={isConnecting || !customApiUrl}
                      className="h-[42px] min-w-[120px]"
                      variant={isApiConnected ? "secondary" : "primary"}
                    >
                      {isConnecting ? <Spinner /> : isApiConnected ? "Connected" : "Connect"}
                    </Button>
                  </div>
                </div>
              )}
            </div>

            {/* File Upload */}
            <div className="flex flex-col sm:flex-row items-center justify-center gap-6">
              <input 
                type="file" 
                accept=".json" 
                ref={fileInputRef}
                onChange={handleFileChange} 
                className="hidden"
              />
              <Button 
                variant="secondary"
                onClick={() => fileInputRef.current?.click()}
                icon={<svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" /></svg>}
              >
                Select JSON File
              </Button>
              <span className={`text-lg font-medium ${file ? 'text-blue-600' : 'text-gray-400'}`}>
                {file ? file.name : 'No file selected'}
              </span>
            </div>

            {/* Instructions */}
            <div className="max-w-3xl mx-auto">
              <label htmlFor="instructions" className="block text-sm font-medium text-gray-700 mb-2">
                Additional Translation Instructions (Optional)
              </label>
              <textarea
                id="instructions"
                rows={3}
                className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-shadow bg-gray-50 text-gray-900"
                placeholder="e.g., Keep specific names in Pinyin, translate 'Sect' as 'Môn phái'..."
                value={instructions}
                onChange={(e) => setInstructions(e.target.value)}
              />
            </div>

            {/* Progress Bar Area */}
            {(status === AppStatus.TRANSLATING || status === AppStatus.PAUSED || translationSession) && renderProgressBar()}

            {/* Translate / Resume Button */}
            <div className="text-center">
              {status === AppStatus.PAUSED ? (
                 <Button 
                  onClick={resumeTranslation}
                  className="w-full sm:w-auto min-w-[200px] bg-yellow-600 hover:bg-yellow-700"
                  icon={<svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>}
                >
                  Resume Translation
                </Button>
              ) : (
                <Button 
                  onClick={startTranslation}
                  disabled={!file || status === AppStatus.TRANSLATING}
                  className="w-full sm:w-auto min-w-[200px]"
                  icon={status === AppStatus.TRANSLATING ? <Spinner /> : <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 5h12M9 3v2m1.048 9.5A18.022 18.022 0 016.412 9m6.088 9h7M11 21l5-10 5 10M12.751 5C11.783 10.77 8.07 15.61 3 18.129" /></svg>}
                >
                  {status === AppStatus.TRANSLATING ? ' Translating...' : `Translate with ${apiProvider === 'gemini' ? 'Gemini' : 'Custom API'}`}
                </Button>
              )}
            </div>

            {errorMsg && (
               <div className={`border-l-4 p-4 rounded-md max-w-3xl mx-auto ${status === AppStatus.SUCCESS ? 'bg-orange-50 border-orange-500' : 'bg-red-50 border-red-500'}`}>
                 <p className={status === AppStatus.SUCCESS ? 'text-orange-700' : 'text-red-700'}>{errorMsg}</p>
               </div>
            )}
          </div>

          {/* Section 2: Results & Creative */}
          {(status === AppStatus.SUCCESS && translatedData) && (
            <div className="space-y-8 animate-fade-in">
              <div className="flex flex-col sm:flex-row items-center justify-between bg-green-50 p-6 rounded-xl border border-green-100">
                <div className="mb-4 sm:mb-0">
                  <h2 className="text-2xl font-bold text-green-800">Translation Complete!</h2>
                  <p className="text-green-600">Your lorebook has been processed successfully.</p>
                </div>
                <Button variant="secondary" onClick={handleDownload} icon={<svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>}>
                  Download JSON
                </Button>
              </div>

              {/* Preview Box */}
              <div className="bg-gray-900 rounded-xl overflow-hidden shadow-inner">
                <div className="bg-gray-800 px-4 py-2 text-xs text-gray-400 font-mono uppercase tracking-wider flex justify-between">
                  <span>Preview (First 50 lines)</span>
                </div>
                <pre className="p-4 text-green-400 font-mono text-sm h-64 overflow-y-auto custom-scrollbar">
                  {JSON.stringify(translatedData, null, 2).slice(0, 5000) + (JSON.stringify(translatedData).length > 5000 ? '...' : '')}
                </pre>
              </div>

              {/* Creative Assistant */}
              <div className="bg-blue-50 border border-blue-100 rounded-xl p-6 sm:p-8">
                <div className="text-center mb-6">
                  <h2 className="text-2xl font-bold text-blue-900 flex items-center justify-center gap-2">
                    <svg className="w-6 h-6 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                    Creative Assistant
                  </h2>
                  <p className="text-blue-700">Expand your lore using the context of your translated entries.</p>
                </div>

                <div className="grid gap-6">
                  <div>
                    <label className="block text-sm font-medium text-blue-900 mb-2">Select Lorebook Entry</label>
                    <select 
                      className="w-full p-3 border border-blue-200 rounded-lg bg-white focus:ring-2 focus:ring-blue-500 outline-none text-gray-700"
                      value={selectedEntryUid}
                      onChange={(e) => setSelectedEntryUid(e.target.value)}
                    >
                      <option value="">-- Choose an entry --</option>
                      {(Object.values(translatedData.entries) as LorebookEntry[]).map((entry) => (
                        <option key={entry.uid} value={entry.uid}>
                          {entry.comment || (entry.key && entry.key[0]) || `Entry ${entry.uid}`}
                        </option>
                      ))}
                    </select>
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-blue-900 mb-2">Your Creative Prompt</label>
                    <textarea 
                      rows={3}
                      className="w-full p-3 border border-blue-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-gray-900"
                      placeholder="e.g., Write a short backstory for this character involving a lost artifact..."
                      value={creativePrompt}
                      onChange={(e) => setCreativePrompt(e.target.value)}
                    />
                  </div>

                  <div className="text-center">
                    <Button 
                      onClick={handleCreativeGenerate} 
                      disabled={isCreativeLoading || !selectedEntryUid || !creativePrompt}
                      className="w-full sm:w-auto"
                      variant="primary"
                    >
                      {isCreativeLoading ? (
                        <span className="flex items-center gap-2">
                          <Spinner /> Generative Magic...
                        </span>
                      ) : (
                        <span className="flex items-center gap-2">
                          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.428 15.428a2 2 0 00-1.022-.547l-2.384-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z" /></svg>
                          Generate Content
                        </span>
                      )}
                    </Button>
                  </div>

                  {creativeOutput && (
                    <div className="mt-6 bg-white rounded-lg p-6 border border-blue-100 shadow-sm">
                      <h3 className="text-lg font-bold text-gray-800 mb-3">Result:</h3>
                      <div className="prose prose-blue max-w-none text-gray-700 whitespace-pre-wrap leading-relaxed">
                        {creativeOutput}
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { translateBatch, generateCreativeContent } from './services/geminiService';
import { Lorebook, LorebookEntry, AppStatus, TranslationSession, ApiProvider, ApiConfig } from './types';
import { Spinner } from './components/Spinner';
import { Button } from './components/Button';

// Regex to identify Vietnamese characters (to skip already translated items)
const VIETNAMESE_REGEX = /[àáạảãâầấậẩẫăằắặẳẵèéẹẻẽêềếệểễìíịỉĩòóọỏõôồốộổỗơờớợởỡùúụủũưừứựửữỳýỵỷỹđ]/i;

const BATCH_SIZE = 50;

const App: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [originalData, setOriginalData] = useState<Lorebook | null>(null);
  const [translatedData, setTranslatedData] = useState<Lorebook | null>(null);
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [instructions, setInstructions] = useState<string>('');
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // API Configuration State
  const [apiProvider, setApiProvider] = useState<ApiProvider>(() => 
    (localStorage.getItem('lorebook_api_provider') as ApiProvider) || 'gemini'
  );
  const [customApiUrl, setCustomApiUrl] = useState<string>(() => 
    localStorage.getItem('lorebook_custom_url') || ''
  );
  const [customApiKey, setCustomApiKey] = useState<string>(() => 
    localStorage.getItem('lorebook_custom_key') || ''
  );
  const [customModels, setCustomModels] = useState<string[]>([]);
  const [selectedCustomModel, setSelectedCustomModel] = useState<string>(() => 
    localStorage.getItem('lorebook_custom_model') || ''
  );
  const [isApiConnected, setIsApiConnected] = useState<boolean>(false);
  const [isConnecting, setIsConnecting] = useState<boolean>(false);

  // Translation Session State (for progress & resume)
  const [translationSession, setTranslationSession] = useState<TranslationSession | null>(null);
  const [progress, setProgress] = useState<number>(0);
  const [skippedBatches, setSkippedBatches] = useState<number>(0);

  // Creative Assistant State
  const [selectedEntryUid, setSelectedEntryUid] = useState<string>('');
  const [creativePrompt, setCreativePrompt] = useState<string>('');
  const [creativeOutput, setCreativeOutput] = useState<string>('');
  const [isCreativeLoading, setIsCreativeLoading] = useState<boolean>(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Persistence Effects
  useEffect(() => { localStorage.setItem('lorebook_api_provider', apiProvider); }, [apiProvider]);
  useEffect(() => { localStorage.setItem('lorebook_custom_url', customApiUrl); }, [customApiUrl]);
  useEffect(() => { localStorage.setItem('lorebook_custom_key', customApiKey); }, [customApiKey]);
  useEffect(() => { 
    if (selectedCustomModel) {
      localStorage.setItem('lorebook_custom_model', selectedCustomModel);
    }
  }, [selectedCustomModel]);

  const handleConnectApi = async () => {
    if (!customApiUrl) {
      setErrorMsg("Please enter an API URL.");
      return;
    }

    setIsConnecting(true);
    setErrorMsg(null);

    try {
      const url = customApiUrl.replace(/\/$/, '') + '/models';
      const headers: Record<string, string> = {
        'Content-Type': 'application/json'
      };
      if (customApiKey) {
        headers['Authorization'] = `Bearer ${customApiKey}`;
      }

      const res = await fetch(url, { headers });
      if (!res.ok) throw new Error('Failed to connect to API');

      const data = await res.json();
      const modelsData = data.data || data.models || [];

      // Extract model IDs
      const modelIds: string[] = modelsData.map((m: any) => 
        typeof m === 'string' ? m : (m.id || m.name)
      );

      if (modelIds.length === 0) throw new Error('No models found in API response');

      setCustomModels(modelIds);

      // Preserve previously selected model if it exists in the new list
      if (selectedCustomModel && modelIds.includes(selectedCustomModel)) {
        setSelectedCustomModel(selectedCustomModel);
      } else {
        setSelectedCustomModel(modelIds[0]);
      }

      setIsApiConnected(true);
    } catch (err: any) {
      console.error(err);
      setErrorMsg(`Connection failed: ${err.message}`);
      setIsApiConnected(false);
    } finally {
      setIsConnecting(false);
    }
  };

  const getApiConfig = (): ApiConfig => {
    return {
      provider: apiProvider,
      baseUrl: customApiUrl,
      apiKey: customApiKey,
      model: selectedCustomModel
    };
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const selectedFile = e.target.files[0];
      setFile(selectedFile);
      setErrorMsg(null);

      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const content = event.target?.result as string;
          const json = JSON.parse(content);
          setOriginalData(json);
          // Reset previous results
          setTranslatedData(null);
          setTranslationSession(null);
          setProgress(0);
          setSkippedBatches(0);
          setStatus(AppStatus.IDLE);
        } catch (err) {
          setErrorMsg("Invalid JSON file format.");
          setFile(null);
        }
      };
      reader.readAsText(selectedFile);
    }
  };

  const extractStrings = (data: Lorebook): Set<string> => {
    const stringsToTranslate = new Set<string>();
    if (!data.entries || typeof data.entries !== 'object') return stringsToTranslate;

    Object.values(data.entries).forEach((entry: LorebookEntry) => {
      // Collect keys
      if (Array.isArray(entry.key)) {
        entry.key.forEach(k => {
          if (k && !VIETNAMESE_REGEX.test(k) && !k.includes('{{user}}') && !k.includes('{{char}}')) {
            stringsToTranslate.add(k);
          }
        });
      }
      // Collect secondary keys
      if (Array.isArray(entry.keysecondary)) {
        entry.keysecondary.forEach(k => {
          if (k && !VIETNAMESE_REGEX.test(k) && !k.includes('{{user}}') && !k.includes('{{char}}')) {
            stringsToTranslate.add(k);
          }
        });
      }
      // Collect comments
      if (typeof entry.comment === 'string' && entry.comment && !VIETNAMESE_REGEX.test(entry.comment)) {
        stringsToTranslate.add(entry.comment);
      }
    });
    return stringsToTranslate;
  };

  const runTranslationLoop = async (session: TranslationSession) => {
    setStatus(AppStatus.TRANSLATING);
    setErrorMsg(null);

    const apiConfig = getApiConfig();

    // Create a local mutable copy of results to accumulate during this run
    const currentResults = { ...session.results };
    let currentIndex = session.currentIndex;
    let localSkipped = 0;

    try {
      while (currentIndex < session.allStrings.length) {
        // Calculate current batch
        const batch = session.allStrings.slice(currentIndex, currentIndex + BATCH_SIZE);

        // Call API
        const batchResult = await translateBatch(batch, instructions, apiConfig);

        if (!batchResult) {
          // Failure: Skip this batch and continue
          console.warn(`Batch starting at index ${currentIndex} failed. Skipping.`);
          localSkipped++;
          setSkippedBatches(prev => prev + 1);
        } else {
          // Success: Update local results
          Object.assign(currentResults, batchResult);
        }

        // Move index regardless of success/failure
        currentIndex += BATCH_SIZE;

        // Update Progress
        const progressPercent = Math.min(100, Math.round((currentIndex / session.allStrings.length) * 100));
        setProgress(progressPercent);

        // Checkpoint state
        setTranslationSession({
          ...session,
          currentIndex: currentIndex,
          results: currentResults
        });
      }

      // Loop Finished
      applyTranslations(session.allStrings, currentResults);
      if (localSkipped > 0 || skippedBatches > 0) {
        setErrorMsg(`Completed with warnings: ${localSkipped + skippedBatches} batches were skipped due to API errors.`);
      }

    } catch (err: any) {
      console.error(err);
      setErrorMsg(err.message || "An unexpected error occurred.");
      setTranslationSession({
        ...session,
        currentIndex: currentIndex,
        results: currentResults
      });
      setStatus(AppStatus.PAUSED);
    }
  };

  const startTranslation = () => {
    if (!originalData) return;
    if (apiProvider === 'custom' && !isApiConnected) {
        setErrorMsg("Please connect to your Custom API first.");
        return;
    }

    // 1. Extract strings
    const strings = extractStrings(originalData);
    if (strings.size === 0) {
      setStatus(AppStatus.SUCCESS);
      setTranslatedData(originalData);
      alert("No translatable content found (or all content appears to be Vietnamese already).");
      return;
    }

    const allStrings = Array.from(strings);

    // 2. Initialize Session
    const newSession: TranslationSession = {
      allStrings,
      currentIndex: 0,
      results: {},
      totalBatches: Math.ceil(allStrings.length / BATCH_SIZE)
    };

    setTranslationSession(newSession);
    setProgress(0);
    setSkippedBatches(0);

    // 3. Start Loop
    runTranslationLoop(newSession);
  };

  const resumeTranslation = () => {
    if (translationSession) {
      runTranslationLoop(translationSession);
    }
  };

  const applyTranslations = (allStrings: string[], results: Record<string, string>) => {
    if (!originalData) return;

    try {
      const workingData: Lorebook = JSON.parse(JSON.stringify(originalData));

      Object.values(workingData.entries).forEach((entry: LorebookEntry) => {
        if (Array.isArray(entry.key)) {
            const newKeys = entry.key
                .map(k => results[k])
                .filter((t): t is string => !!t && !entry.key.includes(t));
            entry.key.push(...newKeys);
        }
        if (Array.isArray(entry.keysecondary)) {
            const newKeys = entry.keysecondary
                .map(k => results[k])
                .filter((t): t is string => !!t && !entry.keysecondary.includes(t));
            entry.keysecondary.push(...newKeys);
        }
        if (typeof entry.comment === 'string' && results[entry.comment]) {
          entry.comment = results[entry.comment];
        }
      });

      setTranslatedData(workingData);
      setStatus(AppStatus.SUCCESS);
      setTranslationSession(null); // Clear session on success
    } catch (e) {
      console.error("Error applying translations:", e);
      setErrorMsg("Failed to apply translations to the JSON structure.");
      setStatus(AppStatus.ERROR);
    }
  };

  const handleDownload = () => {
    if (!translatedData || !file) return;

    const jsonString = JSON.stringify(translatedData, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);

    const a = document.createElement('a');
    a.href = url;
    const nameWithoutExt = file.name.replace(/\.json$/i, '');
    a.download = `${nameWithoutExt}_translated.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleCreativeGenerate = async () => {
    if (!translatedData || !selectedEntryUid || !creativePrompt.trim()) return;
    if (apiProvider === 'custom' && !isApiConnected) {
        setErrorMsg("Please connect to your Custom API first.");
        return;
    }

