    const entry = entries.find(e => e.uid.toString() === selectedEntryUid);
    if (!entry) return;

    setIsCreativeLoading(true);
    setCreativeOutput('');

    const apiConfig = getApiConfig();
    const result = await generateCreativeContent(entry, creativePrompt, apiConfig);

