// Initialize Gemini Client
const geminiClient = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Helper to call Custom API (OpenAI Compatible)
 */
const callCustomApi = async (
  config: ApiConfig,
  messages: Array<{ role: string; content: string }>,
  jsonMode: boolean = false
): Promise<string> => {
  if (!config.baseUrl) throw new Error("API URL is required for custom provider");

  const headers: Record<string, string> = {
    'Content-Type': 'application/json',
  };
  if (config.apiKey) {
    headers['Authorization'] = `Bearer ${config.apiKey}`;
  }

  const body: any = {
    model: config.model || 'gpt-3.5-turbo',
    messages: messages,
    temperature: 0.7,
  };

  if (jsonMode && config.model?.includes('gpt')) {
     body.response_format = { type: "json_object" };
  }

  const url = `${config.baseUrl.replace(/\/$/, '')}/chat/completions`;

  const response = await fetch(url, {
    method: 'POST',
    headers,
    body: JSON.stringify(body)
  });

  if (!response.ok) {
    let errText = await response.text();
    try {
        const errJson = JSON.parse(errText);
        if (errJson.error && errJson.error.message) errText = errJson.error.message;
    } catch (e) {}
    throw new Error(`Custom API Error ${response.status}: ${errText}`);
  }

  const data = await response.json();
  return data.choices?.[0]?.message?.content || "";
};

/**
 * Generates a Lorebook Entry (Name, Keywords, Content) based on a user prompt.
 */
export const generateLorebookEntry = async (
  prompt: string,
  apiConfig: ApiConfig
): Promise<Partial<LorebookEntry> | null> => {

  const systemInstruction = `You are an expert creative writer and world-builder helper. 
  Your task is to generate a character, location, or item for a Lorebook based on the user's request.

  Return ONLY a valid JSON object with the following structure:
  {
    "comment": "The name or title of the entry",
    "key": ["keyword1", "keyword2", "keyword3"],
    "content": "A detailed description of the entry. Keep it engaging and suitable for a story context."
  }
  Do not include markdown formatting like \`\`\`json.`;

  const userMessage = `Create a lorebook entry based on this concept: ${prompt}`;

  try {
    let textResponse = "";

    if (apiConfig.provider === 'custom') {
      textResponse = await callCustomApi(
        apiConfig, 
        [
          { role: "system", content: systemInstruction },
          { role: "user", content: userMessage }
        ],
        true
      );
    } else {
      // Default Gemini SDK
      const response = await geminiClient.models.generateContent({
        model: 'gemini-3-flash-preview', 
        contents: `${systemInstruction}\n\n${userMessage}`,
        config: {
          responseMimeType: 'application/json',
        }
      });
      textResponse = response.text || "";
    }

    if (!textResponse) throw new Error("Empty response received");

    const cleanedResponse = textResponse.replace(/^```json\s*/, '').replace(/```$/, '');
    return JSON.parse(cleanedResponse);

  } catch (error) {
    console.error("Lorebook Generation Error:", error);
    return null;
  }
};

