/**
 * Helper to call Custom API (OpenAI Compatible)
 */
const callCustomApi = async (
  config: ApiConfig,
  messages: Array<{ role: string; content: string }>,
  jsonMode: boolean = false
): Promise<string> => {
  if (!config.baseUrl) throw new Error("API URL is required for custom provider");

  const headers: Record<string, string> = {
    'Content-Type': 'application/json',
  };
  if (config.apiKey) {
    headers['Authorization'] = `Bearer ${config.apiKey}`;
  }

  const body: any = {
    model: config.model || 'gpt-3.5-turbo',
    messages: messages,
    temperature: 0.8,
  };

  if (jsonMode && config.model?.includes('gpt')) {
     body.response_format = { type: "json_object" };
  }

  const url = `${config.baseUrl.replace(/\/$/, '')}/chat/completions`;

  const response = await fetch(url, {
    method: 'POST',
    headers,
    body: JSON.stringify(body)
  });

  if (!response.ok) {
    let errText = await response.text();
    try {
        const errJson = JSON.parse(errText);
        if (errJson.error && errJson.error.message) errText = errJson.error.message;
    } catch (e) {}
    throw new Error(`Custom API Error ${response.status}: ${errText}`);
  }

  const data = await response.json();
  return data.choices?.[0]?.message?.content || "";
};

/**
 * Generates a Lorebook Entry (Name, Keywords, Content) based on a user prompt.
 */
export const generateLorebookEntry = async (
  prompt: string,
  apiConfig: ApiConfig,
  mode: GenerationMode = 'detailed'
): Promise<Partial<LorebookEntry> | null> => {

  // Construct the prompt based on mode
  let fullPrompt = "";
  if (mode === 'detailed') {
    fullPrompt = `${HEAD_OVERRIDE}\n\n${DETAILED_SYSTEM_PROMPT}\n${DETAILED_THINKING_TEMPLATE}\n${DETAILED_OUTPUT_FORMAT}\n\n${PRIORITY_PROMPT}\n\nUser Concept: ${prompt}\n\n${TAIL_CONFIRM}`;
  } else {
    fullPrompt = `${HEAD_OVERRIDE}\n\n${BRIEF_SYSTEM_PROMPT}\n${BRIEF_OUTPUT_FORMAT}\n\n${PRIORITY_PROMPT}\n\nUser Concept: ${prompt}\n\n${TAIL_CONFIRM}`;
  }

  // Add instruction to extract metadata at the end
  const metadataInstruction = `
  \n\n---------------------------------------------------
  SAU KHI HOÀN THÀNH TẤT CẢ CÁC PHẦN TRÊN, BẠN BẮT BUỘC PHẢI THÊM MỘT BLOCK JSON Ở CUỐI CÙNG NHƯ SAU ĐỂ HỆ THỐNG ĐỌC TÊN VÀ TỪ KHÓA:
  \`\`\`json
  {
    "comment": "Tên nhân vật",
    "key": ["Họ Tên", "Tên"]
  }
  \`\`\`
  `;

  fullPrompt += metadataInstruction;

  try {
    let textResponse = "";

    if (apiConfig.provider === 'custom') {
      textResponse = await callCustomApi(
        apiConfig, 
        [
          { role: "system", content: "You are a specialized creative writing assistant." },
          { role: "user", content: fullPrompt }
        ],
        false // Not JSON mode for the main call because we need mixed output (Tags + JSON)
      );
    } else {
      // Default Gemini SDK
      const response = await geminiClient.models.generateContent({
        model: 'gemini-3-flash-preview', 
        contents: fullPrompt,
        config: {
            // We want raw text because the user prompt demands XML tags first, JSON at end
        }
      });
      textResponse = response.text || "";
    }

    if (!textResponse) throw new Error("Empty response received");

    // Parse the response
    // 1. Extract JSON block at the end
    let extractedMetadata = { comment: "New Character", key: [] as string[] };
    const jsonMatch = textResponse.match(/```json\s*([\s\S]*?)\s*```/);

    let contentBody = textResponse;

    if (jsonMatch) {
        try {
            extractedMetadata = JSON.parse(jsonMatch[1]);
            // Remove the metadata JSON from the content body
            contentBody = textResponse.replace(jsonMatch[0], '').trim();
        } catch (e) {
            console.warn("Failed to parse metadata JSON from AI response");
        }
    } else {
        // Fallback: try to find simple JSON object at the end
        const fallbackMatch = textResponse.match(/\{[\s\S]*\}$/);
        if (fallbackMatch) {
             try {
                extractedMetadata = JSON.parse(fallbackMatch[0]);
                contentBody = textResponse.replace(fallbackMatch[0], '').trim();
            } catch (e) {}
        }
    }

    // 2. Remove <Suy_nghĩ> block and its content
    contentBody = contentBody.replace(/<Suy_nghĩ>[\s\S]*?<\/Suy_nghĩ>/gi, '').trim();

    // Clean up content body (remove extra newlines at end)
    contentBody = contentBody.trim();

    return {
        comment: extractedMetadata.comment || "Generated Character",
        key: extractedMetadata.key || [],
        content: contentBody
    };

  } catch (error) {
    console.error("Lorebook Generation Error:", error);
    return null;
  }
};

