  };

  if (jsonMode && config.model?.includes('gpt')) {
     body.response_format = { type: "json_object" };
  }

  const url = `${config.baseUrl.replace(/\/$/, '')}/chat/completions`;

  const response = await fetch(url, {
    method: 'POST',
    headers,
    body: JSON.stringify(body)
  });

  if (!response.ok) {
    let errText = await response.text();
    try {
        const errJson = JSON.parse(errText);
        if (errJson.error && errJson.error.message) errText = errJson.error.message;
    } catch (e) {}
    throw new Error(`Custom API Error ${response.status}: ${errText}`);
  }

  const data = await response.json();
  return data.choices?.[0]?.message?.content || "";
};

/**
 * Generates a list of characters for batch processing
 */
export const generateCharacterList = async (
  world: string,
  quantity: number,
  apiConfig: ApiConfig
): Promise<string[]> => {
  const prompt = `List ${quantity} distinct and major characters from the world/series: "${world}".
  Return ONLY a raw JSON array of strings. Do not include markdown code blocks or explanations.
  Example: ["Character Name 1", "Character Name 2"]`;

  try {
    let textResponse = "";
    if (apiConfig.provider === 'custom') {
        textResponse = await callCustomApi(apiConfig, [{ role: "user", content: prompt }]);
    } else {
        const response = await geminiClient.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
        });
        textResponse = response.text || "";
    }

    // Clean up potentially wrapped JSON in markdown blocks
    const jsonMatch = textResponse.match(/\[[\s\S]*\]/);
    if (jsonMatch) {
        return JSON.parse(jsonMatch[0]);
    }
    return JSON.parse(textResponse);
  } catch (e) {
    console.error("Failed to generate character list", e);
    return [];
  }
};

/**
 * Generates a Lorebook Entry (Name, Keywords, Content) based on a user prompt.
 */
export const generateLorebookEntry = async (
  prompt: string,
  apiConfig: ApiConfig,
  mode: GenerationMode = 'detailed',
  customTemplate?: string
): Promise<Partial<LorebookEntry> | null> => {

  // Construct the prompt based on mode
  let fullPrompt = "";

  if (customTemplate) {
    // Custom template mode: Use Detailed System Logic but replace the Output Format with User's Custom Template
    fullPrompt = `${HEAD_OVERRIDE}\n\n${DETAILED_SYSTEM_PROMPT}\n${DETAILED_THINKING_TEMPLATE}\n\n${customTemplate}\n\n${PRIORITY_PROMPT}\n\nUser Concept: ${prompt}\n\n${TAIL_CONFIRM}`;
  } else if (mode === 'detailed') {
    fullPrompt = `${HEAD_OVERRIDE}\n\n${DETAILED_SYSTEM_PROMPT}\n${DETAILED_THINKING_TEMPLATE}\n${DETAILED_OUTPUT_FORMAT}\n\n${PRIORITY_PROMPT}\n\nUser Concept: ${prompt}\n\n${TAIL_CONFIRM}`;
  } else {
    // Brief mode
    fullPrompt = `${HEAD_OVERRIDE}\n\n${BRIEF_SYSTEM_PROMPT}\n${BRIEF_OUTPUT_FORMAT}\n\n${PRIORITY_PROMPT}\n\nUser Concept: ${prompt}\n\n${TAIL_CONFIRM}`;
  }

  // Add instruction to extract metadata at the end
  const metadataInstruction = `
  \n\n---------------------------------------------------
  SAU KHI HOÀN THÀNH TẤT CẢ CÁC PHẦN TRÊN, BẠN BẮT BUỘC PHẢI THÊM MỘT BLOCK JSON Ở CUỐI CÙNG NHƯ SAU ĐỂ HỆ THỐNG ĐỌC TÊN VÀ TỪ KHÓA:
  \`\`\`json
  {
    "comment": "Tên nhân vật",
    "key": ["Họ Tên", "Tên"]
  }
  \`\`\`
  `;

  fullPrompt += metadataInstruction;

  try {
    let textResponse = "";

    if (apiConfig.provider === 'custom') {
      textResponse = await callCustomApi(
        apiConfig, 
        [
          { role: "system", content: "You are a specialized creative writing assistant." },
          { role: "user", content: fullPrompt }
        ],
        false // Not JSON mode for the main call because we need mixed output (Tags + JSON)
      );
    } else {
      // Default Gemini SDK
      const response = await geminiClient.models.generateContent({
        model: 'gemini-3-flash-preview', 
        contents: fullPrompt,
        config: {
            // We want raw text because the user prompt demands XML tags first, JSON at end
        }
      });
      textResponse = response.text || "";
    }

    if (!textResponse) throw new Error("Empty response received");

    // Parse the response
    // 1. Extract JSON block at the end
    let extractedMetadata = { comment: "New Character", key: [] as string[] };
    const jsonMatch = textResponse.match(/```json\s*([\s\S]*?)\s*```/);

    let contentBody = textResponse;

    if (jsonMatch) {
        try {
            extractedMetadata = JSON.parse(jsonMatch[1]);
            // Remove the metadata JSON from the content body
            contentBody = textResponse.replace(jsonMatch[0], '').trim();
        } catch (e) {
            console.warn("Failed to parse metadata JSON from AI response");
        }
    } else {
        // Fallback: try to find simple JSON object at the end
        const fallbackMatch = textResponse.match(/\{[\s\S]*\}$/);
        if (fallbackMatch) {
             try {
                extractedMetadata = JSON.parse(fallbackMatch[0]);
                contentBody = textResponse.replace(fallbackMatch[0], '').trim();
            } catch (e) {}
        }
    }

    // 2. Remove <Suy_nghĩ> block and its content
    contentBody = contentBody.replace(/<Suy_nghĩ>[\s\S]*?<\/Suy_nghĩ>/gi, '').trim();

    // Clean up content body (remove extra newlines at end)
    contentBody = contentBody.trim();

    return {
        comment: extractedMetadata.comment || "Generated Character",
        key: extractedMetadata.key || [],
        content: contentBody
    };

  } catch (error) {
    console.error("Lorebook Generation Error:", error);
    return null;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { generateLorebookEntry, generateCharacterList } from './services/geminiService';
import { Lorebook, LorebookEntry, AppStatus, ApiProvider, ApiConfig, GenerationMode, LorebookTemplate } from './types';
import { Spinner } from './components/Spinner';
import { Button } from './components/Button';
import { Modal } from './components/Modal';

// Default Template for a new entry
const DEFAULT_ENTRY_TEMPLATE: LorebookEntry = {
  uid: 0,
  key: [],
  keysecondary: [],
  comment: "New Entry",
  content: "",
  constant: false,
  vectorized: false,
  selective: true,
  selectiveLogic: 0,
  addMemo: true,
  order: 100,
  position: 1,
  disable: false,
  ignoreBudget: false,
  excludeRecursion: false,
  preventRecursion: false,
  delayUntilRecursion: false,
  probability: 100,
  useProbability: true,
  depth: 4,
  group: "",
  groupOverride: false,
  groupWeight: 100,
  sticky: 0,
  cooldown: 0,
  delay: 0,
  displayIndex: 0
};

const App: React.FC = () => {
  // --- Data State ---
  const [lorebook, setLorebook] = useState<Lorebook>({ entries: {} });
  const [selectedUid, setSelectedUid] = useState<number | null>(null);
  const [searchQuery, setSearchQuery] = useState<string>("");

  // --- UI/API State ---
  const [showApiConfig, setShowApiConfig] = useState<boolean>(false);
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [generationPrompt, setGenerationPrompt] = useState<string>("");
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // --- Template State ---
  const [customTemplates, setCustomTemplates] = useState<LorebookTemplate[]>(() => {
    const saved = localStorage.getItem('lorebook_templates');
    try { return saved ? JSON.parse(saved) : []; } catch { return []; }
  });
  const [selectedTemplateId, setSelectedTemplateId] = useState<string>('brief');
  const [isTemplateModalOpen, setIsTemplateModalOpen] = useState(false);
  const [newTemplateName, setNewTemplateName] = useState("");
  const [newTemplateContent, setNewTemplateContent] = useState("");

  // --- Batch Generation State ---
  const [isBatchModalOpen, setIsBatchModalOpen] = useState(false);
  const [batchWorld, setBatchWorld] = useState("");
  const [batchQuantity, setBatchQuantity] = useState(5);

  // --- API Configuration State (Persistent) ---
  const [apiProvider, setApiProvider] = useState<ApiProvider>(() => 
    (localStorage.getItem('lorebook_api_provider') as ApiProvider) || 'gemini'
  );
  const [customApiUrl, setCustomApiUrl] = useState<string>(() => 
    localStorage.getItem('lorebook_custom_url') || ''
  );
  const [customApiKey, setCustomApiKey] = useState<string>(() => 
    localStorage.getItem('lorebook_custom_key') || ''
  );
  const [customModels, setCustomModels] = useState<string[]>([]);
  const [selectedCustomModel, setSelectedCustomModel] = useState<string>(() => 
    localStorage.getItem('lorebook_custom_model') || ''
  );
  const [isApiConnected, setIsApiConnected] = useState<boolean>(false);
  const [isConnecting, setIsConnecting] = useState<boolean>(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- Effects ---
  useEffect(() => { localStorage.setItem('lorebook_api_provider', apiProvider); }, [apiProvider]);
  useEffect(() => { localStorage.setItem('lorebook_custom_url', customApiUrl); }, [customApiUrl]);
  useEffect(() => { localStorage.setItem('lorebook_custom_key', customApiKey); }, [customApiKey]);
  useEffect(() => { localStorage.setItem('lorebook_templates', JSON.stringify(customTemplates)); }, [customTemplates]);
  useEffect(() => { 
    if (selectedCustomModel) {
      localStorage.setItem('lorebook_custom_model', selectedCustomModel);
    }
  }, [selectedCustomModel]);

  // --- API Handlers ---
  const handleConnectApi = async () => {
    if (!customApiUrl) return setErrorMsg("Please enter an API URL.");
    setIsConnecting(true);
    setErrorMsg(null);
    try {
      const url = customApiUrl.replace(/\/$/, '') + '/models';
      const headers: Record<string, string> = { 'Content-Type': 'application/json' };
      if (customApiKey) headers['Authorization'] = `Bearer ${customApiKey}`;

      const res = await fetch(url, { headers });
      if (!res.ok) throw new Error('Failed to connect to API');

      const data = await res.json();
      const modelsData = data.data || data.models || [];
      const modelIds: string[] = modelsData.map((m: any) => typeof m === 'string' ? m : (m.id || m.name));

      if (modelIds.length === 0) throw new Error('No models found');
      setCustomModels(modelIds);
      if (selectedCustomModel && modelIds.includes(selectedCustomModel)) {
        setSelectedCustomModel(selectedCustomModel);
      } else {
        setSelectedCustomModel(modelIds[0]);
      }
      setIsApiConnected(true);
    } catch (err: any) {
      setErrorMsg(`Connection failed: ${err.message}`);
      setIsApiConnected(false);
    } finally {
      setIsConnecting(false);
    }
  };

  const getApiConfig = (): ApiConfig => ({
    provider: apiProvider,
    baseUrl: customApiUrl,
    apiKey: customApiKey,
    model: selectedCustomModel
  });

  // --- File Handlers ---
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      try {
        const json = JSON.parse(ev.target?.result as string) as Lorebook;
        if (json.entries) {
          setLorebook(json);
          // Select first entry if available
          const entries = Object.values(json.entries) as LorebookEntry[];
          const firstUid = entries[0]?.uid;
          if (firstUid !== undefined) setSelectedUid(firstUid);
        } else {
          setErrorMsg("Invalid Lorebook format: missing 'entries' object.");
        }
      } catch (err) {
        setErrorMsg("Failed to parse JSON file.");
      }
    };
    reader.readAsText(file);
    e.target.value = ''; // Reset input
  };

  const handleExport = () => {
    const jsonString = JSON.stringify(lorebook, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `lorebook_${new Date().toISOString().slice(0,10)}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  // --- Entry Management ---
  const handleAddEntry = () => {
    const entriesVal = Object.values(lorebook.entries) as LorebookEntry[];
    const uids = entriesVal.map(e => e.uid);
    const newUid = uids.length > 0 ? Math.max(...uids) + 1 : 0;

    const newEntry: LorebookEntry = {
      ...DEFAULT_ENTRY_TEMPLATE,
      uid: newUid,
      displayIndex: newUid
    };

    setLorebook(prev => ({
      ...prev,
      entries: { ...prev.entries, [newUid]: newEntry }
    }));
    setSelectedUid(newUid);
  };

  const handleDeleteEntry = (uid: number) => {
    if (!window.confirm("Are you sure you want to delete this entry?")) return;

    const newEntries = { ...lorebook.entries };
    delete newEntries[uid];

    setLorebook(prev => ({ ...prev, entries: newEntries }));
    if (selectedUid === uid) {
      setSelectedUid(null);
    }
  };

  const handleUpdateEntry = (uid: number, field: keyof LorebookEntry, value: any) => {
    setLorebook(prev => ({
      ...prev,
      entries: {
        ...prev.entries,
        [uid]: {
          ...prev.entries[uid],
          [field]: value
        }
      }
    }));
  };

  // --- Template Management ---
  const handleSaveTemplate = () => {
    if (!newTemplateName.trim() || !newTemplateContent.trim()) {
      alert("Name and Content are required!");
      return;
    }
    const newTemplate: LorebookTemplate = {
      id: crypto.randomUUID(),
      name: newTemplateName.trim(),
      content: newTemplateContent
    };
    setCustomTemplates(prev => [...prev, newTemplate]);
    setSelectedTemplateId(newTemplate.id);
    setIsTemplateModalOpen(false);
    setNewTemplateName("");
    setNewTemplateContent("");
  };

  const handleDeleteTemplate = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm("Delete this template?")) {
      setCustomTemplates(prev => prev.filter(t => t.id !== id));
      if (selectedTemplateId === id) setSelectedTemplateId('brief');
    }
  }

  // --- AI Generation ---
  const handleAiGenerate = async () => {
    if (!generationPrompt.trim()) return;
    if (apiProvider === 'custom' && !isApiConnected) return setErrorMsg("Connect to Custom API first");
    if (selectedUid === null) return;

    setStatus(AppStatus.GENERATING);
    try {
      const config = getApiConfig();

      let mode: GenerationMode = 'brief';
      let customTemplateContent: string | undefined = undefined;

      if (selectedTemplateId === 'detailed') {
        mode = 'detailed';
      } else if (selectedTemplateId === 'brief') {
        mode = 'brief';
      } else {
        const found = customTemplates.find(t => t.id === selectedTemplateId);
        if (found) {
          customTemplateContent = found.content;
        }
      }

      const result = await generateLorebookEntry(generationPrompt, config, mode, customTemplateContent);

      if (result) {
        setLorebook(prev => {
           const entry = prev.entries[selectedUid];
           return {
             ...prev,
             entries: {
               ...prev.entries,
               [selectedUid]: {
                 ...entry,
                 comment: result.comment || entry.comment,
                 key: result.key || entry.key,
                 content: result.content || entry.content
               }
             }
           }
        });
        setGenerationPrompt("");
      } else {
        setErrorMsg("AI failed to generate content.");
      }
    } catch (e: any) {
      setErrorMsg(e.message);
    } finally {
      setStatus(AppStatus.IDLE);
    }
  };

  const handleBatchGenerate = async () => {
    if (!batchWorld.trim()) return alert("Vui lòng nhập tên Thế giới");
    if (apiProvider === 'custom' && !isApiConnected) return setErrorMsg("Connect to Custom API first");

    setIsBatchModalOpen(false);
    setStatus(AppStatus.GENERATING);
    setErrorMsg(null);

    try {
      const config = getApiConfig();

      // 1. Generate List of characters
      const characterList = await generateCharacterList(batchWorld, batchQuantity, config);
      if (!characterList || characterList.length === 0) {
        throw new Error("Không thể tạo danh sách nhân vật.");
      }

      // 2. Prepare Template Mode
      let mode: GenerationMode = 'brief';
      let customTemplateContent: string | undefined = undefined;

      if (selectedTemplateId === 'detailed') mode = 'detailed';
      else if (selectedTemplateId === 'brief') mode = 'brief';
      else {
        const found = customTemplates.find(t => t.id === selectedTemplateId);
        if (found) customTemplateContent = found.content;
      }

      // 3. Process each character sequentially
      for (const charName of characterList) {
        // Create placeholder entry
        let newUid = 0;
        setLorebook(prev => {
          const entriesVal = Object.values(prev.entries) as LorebookEntry[];
          const uids = entriesVal.map(e => e.uid);
          newUid = uids.length > 0 ? Math.max(...uids) + 1 : 0;

          const newEntry: LorebookEntry = {
             ...DEFAULT_ENTRY_TEMPLATE,
             uid: newUid,
             displayIndex: newUid,
             comment: `Generating: ${charName}...`,
             content: "Đang tạo nội dung..."
          };
          return { ...prev, entries: { ...prev.entries, [newUid]: newEntry } };
        });

        // Generate content
        const prompt = `Character: ${charName} from the world of ${batchWorld}`;
        const result = await generateLorebookEntry(prompt, config, mode, customTemplateContent);

        // Update entry
        if (result) {
           setLorebook(prev => {
             const entry = prev.entries[newUid]; // Note: using newUid from closure might be risky if state updates are batched weirdly, but in async loop usually okay. Better to find by latest logic if needed, but here simple ID increment works.
             // Actually, the newUid captured in the closure is the one we JUST set.
             // However, React state setters are async. The 'newUid' var is local, so we can use it to Key the object.
             if(!entry) return prev; // Safety
             return {
               ...prev,
               entries: {
                 ...prev.entries,
                 [newUid]: {
                   ...entry,
                   comment: result.comment || charName,
                   key: result.key || [charName],
                   content: result.content || "Failed to content"
                 }
               }
             }
           });
        }
      }

    } catch (e: any) {
      setErrorMsg(`Batch Error: ${e.message}`);
    } finally {
      setStatus(AppStatus.IDLE);
    }
  };

  // --- Render Helpers ---
  const entriesList = (Object.values(lorebook.entries) as LorebookEntry[])
    .sort((a, b) => (a.displayIndex || 0) - (b.displayIndex || 0))
    .filter(e => e.comment.toLowerCase().includes(searchQuery.toLowerCase()) || e.content.toLowerCase().includes(searchQuery.toLowerCase()));

  const activeEntry = selectedUid !== null ? lorebook.entries[selectedUid] : null;

  return (
    <div className="h-screen flex flex-col bg-gray-100 text-gray-800 font-sans overflow-hidden">

      {/* Header */}
      <header className="bg-white border-b border-gray-200 px-6 py-3 flex items-center justify-between shadow-sm z-10">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white font-bold">L</div>
          <h1 className="text-xl font-bold text-gray-800">Lorebook Maker</h1>
        </div>

        <div className="flex items-center gap-3">
           <Button variant="secondary" className="!py-2 !px-4 text-sm" onClick={() => fileInputRef.current?.click()}>
             Import JSON
           </Button>
           <input type="file" ref={fileInputRef} onChange={handleFileUpload} accept=".json" className="hidden" />

           <Button variant="primary" className="!py-2 !px-4 text-sm" onClick={handleExport}>
             Export JSON
           </Button>

           <button 
            onClick={() => setShowApiConfig(!showApiConfig)}
            className={`p-2 rounded-full transition-colors ${showApiConfig ? 'bg-blue-100 text-blue-600' : 'hover:bg-gray-100 text-gray-500'}`}
            title="API Settings"
           >
             <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
           </button>
        </div>
      </header>

      {/* API Config Modal/Panel */}
      {showApiConfig && (
        <div className="bg-gray-50 border-b border-gray-200 p-6 animate-fade-in shadow-inner">
             <div className="max-w-4xl mx-auto">
              <h3 className="text-lg font-semibold text-gray-800 mb-4">API Configuration</h3>
              <div className="flex gap-4 mb-4">
                <button 
                  onClick={() => setApiProvider('gemini')}
                  className={`flex-1 py-2 px-4 rounded-lg font-medium transition-colors ${apiProvider === 'gemini' ? 'bg-blue-600 text-white' : 'bg-white text-gray-700 border border-gray-300'}`}
                >
                  Google Gemini
                </button>
                <button 
                  onClick={() => setApiProvider('custom')}
                  className={`flex-1 py-2 px-4 rounded-lg font-medium transition-colors ${apiProvider === 'custom' ? 'bg-blue-600 text-white' : 'bg-white text-gray-700 border border-gray-300'}`}
                >
                  Custom API
                </button>
              </div>

              {apiProvider === 'custom' && (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 items-end">
                   <div>
                      <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">API URL</label>
                      <input type="text" value={customApiUrl} onChange={(e) => setCustomApiUrl(e.target.value)} className="w-full p-2 border border-gray-300 rounded text-gray-900 bg-white" placeholder="https://api.openai.com/v1" />
                   </div>
                   <div>
                      <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">API Key</label>
                      <input type="password" value={customApiKey} onChange={(e) => setCustomApiKey(e.target.value)} className="w-full p-2 border border-gray-300 rounded text-gray-900 bg-white" placeholder="sk-..." />
                   </div>
                   <div>
                      <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">Model</label>
                      <select value={selectedCustomModel} onChange={(e) => setSelectedCustomModel(e.target.value)} disabled={!isApiConnected} className="w-full p-2 border border-gray-300 rounded text-gray-900 bg-white">
                        {customModels.map(m => <option key={m} value={m}>{m}</option>)}
                        {!isApiConnected && <option>Connect first...</option>}
                      </select>
                   </div>
                   <Button onClick={handleConnectApi} disabled={isConnecting} className="h-[42px]">
                      {isConnecting ? <Spinner /> : isApiConnected ? "Connected" : "Connect"}
                   </Button>
                </div>
              )}
             </div>
        </div>
      )}

      {/* Main Content: Split View */}
      <div className="flex-1 flex overflow-hidden">

        {/* Sidebar: Entry List */}
        <aside className="w-80 bg-white border-r border-gray-200 flex flex-col">
          <div className="p-4 border-b border-gray-100">
            <input 
              type="text" 
              placeholder="Search entries..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full p-2 bg-gray-100 border-none rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-gray-800"
            />
          </div>

          <div className="flex-1 overflow-y-auto">
            {entriesList.length === 0 ? (
              <div className="p-8 text-center text-gray-400 text-sm">No entries found.</div>
            ) : (
              <ul>
                {entriesList.map(entry => (
                  <li key={entry.uid}>
                    <button
                      onClick={() => setSelectedUid(entry.uid)}
